export const ASSET_STYLE_PROFILES = Object.freeze([
  "consulting-2p5d",
  "publication-line",
  "minimal-flat",
  "dark-talk",
  "risk-warning",
  "scientific-editorial-realism"
]);

export function isHeroAsset(assetOrId) {
  const id = typeof assetOrId === "string" ? assetOrId : assetOrId?.id;
  return HERO_ASSET_IDS.includes(id);
}

export function normalizeAssetStyleProfile(value) {
  if (ASSET_STYLE_PROFILES.includes(value)) return value;
  if (value === "outline") return "publication-line";
  if (value === "filled") return "minimal-flat";
  if (value === "dark") return "dark-talk";
  if (value === "warning") return "risk-warning";
  return "consulting-2p5d";
}

export function commercialAssetRecipe(assetOrId) {
  const id = typeof assetOrId === "string" ? assetOrId : assetOrId?.id;
  const family = typeof assetOrId === "string" ? inferFamily(id) : assetOrId?.family ?? assetOrId?.renderSpec?.family ?? inferFamily(id);
  return isHeroAsset(id) ? `hero-${id}` : `standard-${family}`;
}

export function renderCommercialAssetDefs() {
  return [
    `<filter id="asset-contact-shadow" x="-35%" y="-35%" width="170%" height="170%" color-interpolation-filters="sRGB"><feGaussianBlur in="SourceAlpha" stdDeviation="3.5" result="blur"/><feOffset in="blur" dx="0" dy="5" result="offset"/><feColorMatrix in="offset" type="matrix" values="0 0 0 0 0.05 0 0 0 0 0.09 0 0 0 0 0.16 0 0 0 0.22 0" result="shadow"/><feMerge><feMergeNode in="shadow"/><feMergeNode in="SourceGraphic"/></feMerge></filter>`,
    `<filter id="asset-soft-shadow" x="-34%" y="-38%" width="168%" height="176%" color-interpolation-filters="sRGB"><feGaussianBlur in="SourceAlpha" stdDeviation="2.2" result="ambient-blur"/><feOffset in="ambient-blur" dx="0" dy="2" result="ambient-offset"/><feColorMatrix in="ambient-offset" type="matrix" values="0 0 0 0 0.05 0 0 0 0 0.09 0 0 0 0 0.16 0 0 0 0.12 0" result="ambient-shadow"/><feGaussianBlur in="SourceAlpha" stdDeviation="9" result="drop-blur"/><feOffset in="drop-blur" dx="0" dy="12" result="drop-offset"/><feColorMatrix in="drop-offset" type="matrix" values="0 0 0 0 0.05 0 0 0 0 0.09 0 0 0 0 0.16 0 0 0 0.1 0" result="drop-shadow"/><feMerge><feMergeNode in="drop-shadow"/><feMergeNode in="ambient-shadow"/><feMergeNode in="SourceGraphic"/></feMerge></filter>`,
    `<filter id="asset-warning-glow" x="-45%" y="-45%" width="190%" height="190%" color-interpolation-filters="sRGB"><feGaussianBlur stdDeviation="5" result="glow"/><feColorMatrix in="glow" type="matrix" values="0 0 0 0 0.86 0 0 0 0 0.15 0 0 0 0 0.15 0 0 0 0.38 0"/><feMerge><feMergeNode/><feMergeNode in="SourceGraphic"/></feMerge></filter>`,
    `<radialGradient id="asset-body-depth" cx="32%" cy="24%" r="82%"><stop offset="0%" stop-color="#ffffff" stop-opacity="0.78"/><stop offset="48%" stop-color="#ffffff" stop-opacity="0.24"/><stop offset="100%" stop-color="#0f172a" stop-opacity="0.05"/></radialGradient>`,
    `<linearGradient id="asset-glass-highlight" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#ffffff" stop-opacity="0.62"/><stop offset="58%" stop-color="#ffffff" stop-opacity="0.1"/><stop offset="100%" stop-color="#ffffff" stop-opacity="0"/></linearGradient>`
  ].join("");
}

export function renderCommercialAssetGlyph(assetOrId, width, height, options = {}) {
  const asset = normalizeAsset(assetOrId);
  const appearance = normalizeAppearance(options.appearance ?? options);
  const styleProfile = normalizeAssetStyleProfile(options.styleProfile ?? appearance.styleProfile ?? options.variant);
  const detailLevel = ["low", "medium", "high"].includes(options.detailLevel ?? appearance.detailLevel)
    ? (options.detailLevel ?? appearance.detailLevel)
    : "medium";
  const palette = variantPalette(asset, options.variant ?? "soft-3d-vector", appearance, styleProfile, detailLevel);
  const recipe = asset.renderSpec?.assetRecipe ?? commercialAssetRecipe(asset);
  const qualityTier = asset.qualityTier ?? (isHeroAsset(asset.id) ? "hero" : "standard");
  const body = finishRenderedAssetMarkup(scaleStrokeWidths(renderRecipe(asset, width, height, palette), palette.strokeScale), palette);
  const labelVisible = options.showLabel !== false && appearance.labelVisible !== false;
  const label = labelVisible ? renderLabel(options.label ?? asset.name, width, height, palette) : "";
  const anchors = renderAnchors(width, height);
  return `<g class="premium-asset commercial-premium-asset style-${escapeXml(styleProfile)}" data-asset-id="${escapeXml(asset.id)}" data-family="${escapeXml(asset.family)}" data-quality-tier="${escapeXml(qualityTier)}" data-recipe="${escapeXml(recipe)}" data-variant="${escapeXml(options.variant ?? "soft-3d-vector")}" data-style-profile="${escapeXml(styleProfile)}" data-detail-level="${escapeXml(detailLevel)}" data-accent="${escapeXml(palette.accent)}" data-stroke-width="${escapeXml(String(appearance.strokeWidth ?? 2))}">${body}${anchors}${label}</g>`;
}

