function cellNeighborhoodAsset(cx, cy, s, palette) {
  const cells = [
    [0, 1, 0.58, palette.fill, palette.accent],
    [-32, -14, 0.43, palette.secondary, palette.stroke],
    [31, -17, 0.4, palette.secondary, palette.stroke],
    [-27, 25, 0.39, palette.fill, palette.stroke],
    [28, 25, 0.42, "#ffffff", palette.accent],
    [4, -36, 0.35, palette.secondary, palette.accent]
  ];
  const links = cells.slice(1).map(([x, y], index) => `<path class="asset-cell-neighborhood-edge asset-neighborhood-adjacency-edge" data-neighbor-edge="${index + 1}" d="M${fmt(cx)},${fmt(cy + 2 * s)} C${fmt(cx + (x * 0.32 + (index % 2 ? 7 : -7)) * s)},${fmt(cy + (y * 0.55) * s)} ${fmt(cx + (x * 0.72) * s)},${fmt(cy + (y * 0.82) * s)} ${fmt(cx + x * s)},${fmt(cy + y * s)}" fill="none" stroke="${index % 2 ? palette.stroke : palette.accent}" stroke-width="${fmt(1.7 * s)}" stroke-linecap="round" opacity="0.56"/>`).join("");
  const renderedCells = cells.map(([x, y, scale, fill, stroke], index) => {
    const px = cx + x * s;
    const py = cy + y * s;
    const cellPath = organicPath(px, py, s * scale, index === 0 ? 8 : 6 + (index % 3), index === 0 ? 0.95 : 0.86);
    const nucleusFill = index === 0 ? palette.secondary : "#ffffff";
    return `<g class="asset-neighborhood-cell ${index === 0 ? "asset-neighborhood-index-cell" : "asset-neighborhood-context-cell"}" data-neighbor-index="${index}"><path class="asset-neighborhood-cell-body" d="${cellPath}" fill="${fill}" stroke="${stroke}" stroke-width="${fmt((index === 0 ? 2.1 : 1.55) * s)}" stroke-linejoin="round"/><ellipse class="asset-neighborhood-cell-nucleus" cx="${fmt(px - 3 * s * scale)}" cy="${fmt(py + 1 * s * scale)}" rx="${fmt(9 * s * scale)}" ry="${fmt(7 * s * scale)}" fill="${nucleusFill}" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}" opacity="${index === 0 ? 1 : 0.82}"/></g>`;
  }).join("");
  const neighborhoodRing = `<path class="asset-cell-neighborhood-radius asset-neighborhood-boundary-ring" d="M${fmt(cx - 49 * s)},${fmt(cy - 18 * s)} C${fmt(cx - 37 * s)},${fmt(cy - 54 * s)} ${fmt(cx + 38 * s)},${fmt(cy - 55 * s)} ${fmt(cx + 49 * s)},${fmt(cy - 16 * s)} C${fmt(cx + 61 * s)},${fmt(cy + 29 * s)} ${fmt(cx + 22 * s)},${fmt(cy + 53 * s)} ${fmt(cx - 22 * s)},${fmt(cy + 45 * s)} C${fmt(cx - 55 * s)},${fmt(cy + 39 * s)} ${fmt(cx - 63 * s)},${fmt(cy + 8 * s)} ${fmt(cx - 49 * s)},${fmt(cy - 18 * s)} Z" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.8 * s)}" stroke-dasharray="${fmt(5 * s)} ${fmt(5 * s)}" opacity="0.52"/>`;
  return `${baseLayer(cx, cy, s, palette)}<g class="asset-cell-neighborhood asset-neighborhood-graph" filter="url(#asset-soft-shadow)">${links}${neighborhoodRing}${renderedCells}</g><circle class="asset-neighborhood-status-node" cx="${fmt(cx + 36 * s)}" cy="${fmt(cy - 38 * s)}" r="${fmt(6 * s)}" fill="${palette.accent}"/><path class="asset-neighborhood-status-cross" d="M${fmt(cx + 36 * s)},${fmt(cy - 38 * s)} v${fmt(16 * s)} M${fmt(cx + 28 * s)},${fmt(cy - 30 * s)} h${fmt(16 * s)}" stroke="#ffffff" stroke-width="${fmt(1.7 * s)}" stroke-linecap="round"/>${shine(cx - 22 * s, cy - 30 * s, s)}`;
}

