  const fateArrows = `<path class="asset-stem-cell-fate-arrow asset-stem-cell-differentiation-arrow" d="M${fmt(cx - 13 * s)},${fmt(cy + 20 * s)} C${fmt(cx - 26 * s)},${fmt(cy + 27 * s)} ${fmt(cx - 30 * s)},${fmt(cy + 29 * s)} ${fmt(cx - 38 * s)},${fmt(cy + 33 * s)} M${fmt(cx - 38 * s)},${fmt(cy + 33 * s)} l${fmt(9 * s)},${fmt(-1 * s)} l${fmt(-5 * s)},${fmt(-7 * s)} M${fmt(cx + 3 * s)},${fmt(cy + 22 * s)} C${fmt(cx + 18 * s)},${fmt(cy + 28 * s)} ${fmt(cx + 27 * s)},${fmt(cy + 28 * s)} ${fmt(cx + 38 * s)},${fmt(cy + 34 * s)} M${fmt(cx + 38 * s)},${fmt(cy + 34 * s)} l${fmt(-9 * s)},${fmt(-1 * s)} l${fmt(5 * s)},${fmt(-7 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.2 * s)}" stroke-linecap="round" stroke-linejoin="round"/>`;
