function hepatocyteAsset(cx, cy, s, palette) {
  const cells = [[-21, -9], [12, -14], [-4, 17]].map(([x, y], index) => `<path class="asset-hepatocyte-cell-plate" d="M${fmt(cx + x * s - 17 * s)},${fmt(cy + y * s - 9 * s)} l${fmt(14 * s)},${fmt(-11 * s)} l${fmt(22 * s)},${fmt(4 * s)} l${fmt(9 * s)},${fmt(17 * s)} l${fmt(-13 * s)},${fmt(15 * s)} l${fmt(-24 * s)},${fmt(1 * s)} Z" fill="${index === 1 ? palette.secondary : palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(1.8 * s)}" filter="${index === 0 ? "url(#asset-soft-shadow)" : "none"}"/><ellipse class="asset-hepatocyte-nucleus" cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s + 1 * s)}" rx="${fmt(6 * s)}" ry="${fmt(5 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.3 * s)}"/>`).join("");
  return `${baseLayer(cx, cy, s, palette)}<g class="asset-cell-hepatocyte asset-hepatocyte-cell-plate asset-hepatocyte-sinusoid asset-hepatocyte-nucleus asset-liver-cell-context" filter="url(#asset-soft-shadow)">${cells}<path class="asset-hepatocyte-sinusoid" d="M${fmt(cx - 40 * s)},${fmt(cy + 3 * s)} C${fmt(cx - 12 * s)},${fmt(cy - 10 * s)} ${fmt(cx + 20 * s)},${fmt(cy + 3 * s)} ${fmt(cx + 43 * s)},${fmt(cy - 12 * s)} M${fmt(cx - 24 * s)},${fmt(cy + 28 * s)} C${fmt(cx + 2 * s)},${fmt(cy + 10 * s)} ${fmt(cx + 25 * s)},${fmt(cy + 30 * s)} ${fmt(cx + 42 * s)},${fmt(cy + 14 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.1 * s)}" stroke-linecap="round" opacity="0.78"/><circle class="asset-hepatocyte-portal-dot" cx="${fmt(cx + 43 * s)}" cy="${fmt(cy - 12 * s)}" r="${fmt(4.5 * s)}" fill="${palette.accent}"/><circle class="asset-hepatocyte-portal-dot" cx="${fmt(cx - 41 * s)}" cy="${fmt(cy + 3 * s)}" r="${fmt(4 * s)}" fill="${palette.accent}" opacity="0.72"/></g>`;
}

function bloodSampleAsset(cx, cy, s, palette) {
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-blood-sample asset-blood-sample-tube asset-blood-plasma-layer asset-red-blood-cells asset-clinical-specimen" filter="url(#asset-soft-shadow)"><path class="asset-blood-sample-tube" d="M${fmt(cx - 23 * s)},${fmt(cy - 37 * s)} h${fmt(46 * s)} q${fmt(8 * s)},0 ${fmt(8 * s)},${fmt(8 * s)} v${fmt(57 * s)} q0,${fmt(10 * s)} ${fmt(-10 * s)},${fmt(10 * s)} h${fmt(-42 * s)} q${fmt(-10 * s)},0 ${fmt(-10 * s)},${fmt(-10 * s)} v${fmt(-57 * s)} q0,${fmt(-8 * s)} ${fmt(8 * s)},${fmt(-8 * s)} Z" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(2 * s)}"/><path class="asset-blood-plasma-layer" d="M${fmt(cx - 25 * s)},${fmt(cy - 4 * s)} h${fmt(50 * s)} v${fmt(31 * s)} q0,${fmt(8 * s)} ${fmt(-8 * s)},${fmt(8 * s)} h${fmt(-34 * s)} q${fmt(-8 * s)},0 ${fmt(-8 * s)},${fmt(-8 * s)} Z" fill="#ef4444" opacity="0.78"/><ellipse class="asset-red-blood-cell" cx="${fmt(cx - 10 * s)}" cy="${fmt(cy + 11 * s)}" rx="${fmt(8 * s)}" ry="${fmt(5 * s)}" fill="#fee2e2" stroke="#ef4444" stroke-width="${fmt(1.4 * s)}"/><ellipse class="asset-red-blood-cell" cx="${fmt(cx + 12 * s)}" cy="${fmt(cy + 23 * s)}" rx="${fmt(7 * s)}" ry="${fmt(5 * s)}" fill="#fee2e2" stroke="#ef4444" stroke-width="${fmt(1.4 * s)}"/><path class="asset-blood-tube-cap" d="M${fmt(cx - 32 * s)},${fmt(cy - 42 * s)} h${fmt(64 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(4 * s)}" stroke-linecap="round"/><path class="asset-blood-sample-alert" d="M${fmt(cx + 39 * s)},${fmt(cy - 25 * s)} l${fmt(9 * s)},${fmt(14 * s)} h${fmt(-18 * s)} Z" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.7 * s)}"/><path class="asset-blood-tube-label" d="M${fmt(cx - 13 * s)},${fmt(cy - 20 * s)} h${fmt(26 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.8 * s)}" stroke-linecap="round"/></g>`;
}

function tissueSectionAsset(cx, cy, s, palette) {
  const slide = `<rect class="asset-tissue-slide" x="${fmt(cx - 55 * s)}" y="${fmt(cy + 21 * s)}" width="${fmt(110 * s)}" height="${fmt(18 * s)}" rx="${fmt(7 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.25 * s)}" opacity="0.58"/><path class="asset-tissue-slide-label" d="M${fmt(cx - 42 * s)},${fmt(cy + 31 * s)} h${fmt(84 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.2 * s)}" opacity="0.5" stroke-linecap="round"/>`;
  const specimen = `M${fmt(cx - 50 * s)},${fmt(cy - 18 * s)} C${fmt(cx - 33 * s)},${fmt(cy - 42 * s)} ${fmt(cx + 17 * s)},${fmt(cy - 43 * s)} ${fmt(cx + 48 * s)},${fmt(cy - 17 * s)} C${fmt(cx + 56 * s)},${fmt(cy - 7 * s)} ${fmt(cx + 43 * s)},${fmt(cy + 13 * s)} ${fmt(cx + 18 * s)},${fmt(cy + 20 * s)} C${fmt(cx - 10 * s)},${fmt(cy + 29 * s)} ${fmt(cx - 48 * s)},${fmt(cy + 18 * s)} ${fmt(cx - 55 * s)},${fmt(cy + 2 * s)} C${fmt(cx - 58 * s)},${fmt(cy - 7 * s)} ${fmt(cx - 56 * s)},${fmt(cy - 13 * s)} ${fmt(cx - 50 * s)},${fmt(cy - 18 * s)} Z`;
  const layers = `<path class="asset-tissue-layer" data-layer="epithelium" d="M${fmt(cx - 45 * s)},${fmt(cy - 7 * s)} C${fmt(cx - 18 * s)},${fmt(cy - 20 * s)} ${fmt(cx + 18 * s)},${fmt(cy - 14 * s)} ${fmt(cx + 43 * s)},${fmt(cy - 1 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.25 * s)}" opacity="0.68" stroke-linecap="round"/><path class="asset-tissue-layer" data-layer="stroma" d="M${fmt(cx - 42 * s)},${fmt(cy + 7 * s)} C${fmt(cx - 14 * s)},${fmt(cy - 2 * s)} ${fmt(cx + 15 * s)},${fmt(cy + 4 * s)} ${fmt(cx + 40 * s)},${fmt(cy + 12 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(2.05 * s)}" opacity="0.68" stroke-linecap="round"/><path class="asset-tissue-layer" data-layer="basal" d="M${fmt(cx - 39 * s)},${fmt(cy + 19 * s)} C${fmt(cx - 12 * s)},${fmt(cy + 27 * s)} ${fmt(cx + 15 * s)},${fmt(cy + 24 * s)} ${fmt(cx + 37 * s)},${fmt(cy + 13 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(1.25 * s)}" opacity="0.34" stroke-linecap="round"/>`;
  const lobules = [[-27, -13, 16, 8], [6, -17, 18, 9], [25, 3, 15, 8], [-16, 11, 18, 8]].map(([x, y, rx, ry], index) => `<ellipse class="asset-tissue-region-boundary" data-region-index="${index}" cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" rx="${fmt(rx * s)}" ry="${fmt(ry * s)}" fill="${index % 2 ? palette.secondary : "#ffffff"}" stroke="${palette.accent}" stroke-width="${fmt(0.95 * s)}" opacity="${fmt(index % 2 ? 0.28 : 0.34)}" transform="rotate(${index * 17 - 12} ${fmt(cx + x * s)} ${fmt(cy + y * s)})"/>`).join("");
  const capillary = `<path class="asset-tissue-capillary" d="M${fmt(cx - 42 * s)},${fmt(cy + 13 * s)} C${fmt(cx - 22 * s)},${fmt(cy - 4 * s)} ${fmt(cx + 7 * s)},${fmt(cy + 25 * s)} ${fmt(cx + 40 * s)},${fmt(cy + 2 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(1.3 * s)}" opacity="0.34" stroke-linecap="round"/><circle class="asset-tissue-capillary" cx="${fmt(cx - 39 * s)}" cy="${fmt(cy + 11 * s)}" r="${fmt(2.8 * s)}" fill="${palette.stroke}" opacity="0.31"/><circle class="asset-tissue-capillary" cx="${fmt(cx + 38 * s)}" cy="${fmt(cy + 3 * s)}" r="${fmt(2.6 * s)}" fill="${palette.stroke}" opacity="0.27"/>`;
  const cells = [[-34, -18], [-21, -25], [-6, -21], [11, -18], [29, -11], [-29, -3], [-13, 0], [5, 1], [24, 8], [-17, 14], [2, 17], [18, 18]].map(([x, y], index) => `<ellipse class="asset-tissue-nucleus" data-nucleus-index="${index}" cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" rx="${fmt((index % 2 ? 3.2 : 4.1) * s)}" ry="${fmt((index % 3 ? 1.9 : 2.3) * s)}" fill="${palette.accent}" opacity="${fmt(index % 2 ? 0.52 : 0.69)}" transform="rotate(${index * 31} ${fmt(cx + x * s)} ${fmt(cy + y * s)})"/>`).join("");
  return `${baseLayer(cx, cy, s, palette)}<g filter="url(#asset-soft-shadow)">${slide}<path class="asset-tissue-specimen" d="${specimen}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.25 * s)}"/><path class="asset-tissue-glass" d="${specimen}" fill="url(#asset-glass-highlight)" opacity="0.42"/><path class="asset-tissue-rim-highlight" d="${specimen}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.35 * s)}" opacity="0.56"/>${lobules}${layers}${capillary}${cells}</g>`;
}

function histologyTileAsset(cx, cy, s, palette) {
  const field = `<rect class="asset-histology-slide-frame" x="${fmt(cx - 50 * s)}" y="${fmt(cy - 37 * s)}" width="${fmt(100 * s)}" height="${fmt(78 * s)}" rx="${fmt(13 * s)}" fill="#ffffff" stroke="${palette.stroke}" stroke-width="${fmt(2.05 * s)}"/><rect class="asset-histology-tissue-field" x="${fmt(cx - 45 * s)}" y="${fmt(cy - 31 * s)}" width="${fmt(90 * s)}" height="${fmt(66 * s)}" rx="${fmt(11 * s)}" fill="${palette.fill}" stroke="${palette.accent}" stroke-width="${fmt(1 * s)}" opacity="0.5"/>`;
  const glands = [[-25, -12, 13, 8], [7, -16, 11, 7], [27, 3, 13, 8], [-15, 15, 12, 7], [14, 18, 10, 6]].map(([x, y, rx, ry], index) => `<g class="asset-histology-gland"><ellipse cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" rx="${fmt(rx * s)}" ry="${fmt(ry * s)}" fill="${index % 2 ? palette.secondary : "#ffffff"}" stroke="${palette.accent}" stroke-width="${fmt(1.35 * s)}" opacity="0.82"/><ellipse cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" rx="${fmt(rx * 0.42 * s)}" ry="${fmt(ry * 0.38 * s)}" fill="${palette.fill}" stroke="${palette.accent}" stroke-width="${fmt(0.8 * s)}" opacity="0.88"/></g>`).join("");
  const stromalLines = [-36, -22, -8, 8, 24, 38].map((x, index) => `<path class="asset-histology-stromal-fiber" d="M${fmt(cx + x * s)},${fmt(cy - 30 * s)} C${fmt(cx + (x + 14) * s)},${fmt(cy - 10 * s)} ${fmt(cx + (x - 10) * s)},${fmt(cy + 9 * s)} ${fmt(cx + (x + 7) * s)},${fmt(cy + 31 * s)}" fill="none" stroke="${index % 2 ? palette.stroke : palette.accent}" stroke-width="${fmt(1.5 * s)}" opacity="0.36" stroke-linecap="round"/>`).join("");
  const nuclei = Array.from({ length: 28 }, (_, i) => {
    const px = cx + (((i * 23) % 80) - 40) * s;
    const py = cy + (((i * 37) % 56) - 28) * s;
    return `<ellipse class="asset-histology-nucleus-speckle" cx="${fmt(px)}" cy="${fmt(py)}" rx="${fmt(2.1 * s)}" ry="${fmt(1.25 * s)}" fill="${palette.accent}" opacity="0.54" transform="rotate(${(i * 31) % 180} ${fmt(px)} ${fmt(py)})"/>`;
  }).join("");
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-histology-section asset-histology-slide-frame asset-histology-tissue-field asset-histology-gland asset-histology-nucleus-speckle" filter="url(#asset-soft-shadow)">${field}${stromalLines}${glands}${nuclei}<path class="asset-histology-rim-highlight" d="M${fmt(cx - 42 * s)},${fmt(cy - 31 * s)} h${fmt(31 * s)}" stroke="#ffffff" stroke-width="${fmt(1.7 * s)}" opacity="0.62" stroke-linecap="round"/></g>`;
}

function tissuePatch(cx, cy, s, palette, mode) {
  const isHistology = mode === "histology";
  const isRegion = mode === "region";
  const isSection = mode === "section";
  const bg = isHistology
    ? `M${fmt(cx - 51 * s)},${fmt(cy - 34 * s)} H${fmt(cx + 42 * s)} C${fmt(cx + 56 * s)},${fmt(cy - 33 * s)} ${fmt(cx + 58 * s)},${fmt(cy - 18 * s)} ${fmt(cx + 49 * s)},${fmt(cy - 7 * s)} C${fmt(cx + 57 * s)},${fmt(cy + 12 * s)} ${fmt(cx + 42 * s)},${fmt(cy + 34 * s)} ${fmt(cx + 14 * s)},${fmt(cy + 36 * s)} H${fmt(cx - 45 * s)} C${fmt(cx - 58 * s)},${fmt(cy + 35 * s)} ${fmt(cx - 58 * s)},${fmt(cy + 17 * s)} ${fmt(cx - 48 * s)},${fmt(cy + 6 * s)} C${fmt(cx - 56 * s)},${fmt(cy - 12 * s)} ${fmt(cx - 54 * s)},${fmt(cy - 30 * s)} ${fmt(cx - 51 * s)},${fmt(cy - 34 * s)} Z`
    : isRegion
      ? `M${fmt(cx - 49 * s)},${fmt(cy - 27 * s)} C${fmt(cx - 32 * s)},${fmt(cy - 52 * s)} ${fmt(cx + 27 * s)},${fmt(cy - 48 * s)} ${fmt(cx + 49 * s)},${fmt(cy - 17 * s)} C${fmt(cx + 68 * s)},${fmt(cy + 9 * s)} ${fmt(cx + 40 * s)},${fmt(cy + 41 * s)} ${fmt(cx - 2 * s)},${fmt(cy + 42 * s)} C${fmt(cx - 43 * s)},${fmt(cy + 43 * s)} ${fmt(cx - 70 * s)},${fmt(cy + 12 * s)} ${fmt(cx - 49 * s)},${fmt(cy - 27 * s)} Z`
      : `M${fmt(cx - 53 * s)},${fmt(cy - 17 * s)} C${fmt(cx - 35 * s)},${fmt(cy - 42 * s)} ${fmt(cx + 22 * s)},${fmt(cy - 43 * s)} ${fmt(cx + 51 * s)},${fmt(cy - 18 * s)} C${fmt(cx + 60 * s)},${fmt(cy - 4 * s)} ${fmt(cx + 49 * s)},${fmt(cy + 18 * s)} ${fmt(cx + 22 * s)},${fmt(cy + 29 * s)} C${fmt(cx - 13 * s)},${fmt(cy + 43 * s)} ${fmt(cx - 52 * s)},${fmt(cy + 29 * s)} ${fmt(cx - 58 * s)},${fmt(cy + 7 * s)} C${fmt(cx - 61 * s)},${fmt(cy - 3 * s)} ${fmt(cx - 59 * s)},${fmt(cy - 11 * s)} ${fmt(cx - 53 * s)},${fmt(cy - 17 * s)} Z`;
  const capsule = `<path d="${bg}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.2 * s)}"/><path d="${bg}" fill="url(#asset-glass-highlight)" opacity="${isHistology ? 0.34 : 0.42}"/><path d="${bg}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.35 * s)}" opacity="0.56"/>`;
  const stromalFibers = [-38, -23, -8, 9, 26, 41].map((x, index) => `<path class="asset-tissue-fiber" d="M${fmt(cx + x * s)},${fmt(cy - 31 * s)} C${fmt(cx + (x + 16) * s)},${fmt(cy - 15 * s)} ${fmt(cx + (x - 15) * s)},${fmt(cy + 10 * s)} ${fmt(cx + (x + 9) * s)},${fmt(cy + 34 * s)}" fill="none" stroke="${index % 2 ? palette.stroke : palette.accent}" stroke-width="${fmt((isHistology ? 2.15 : 1.55) * s)}" opacity="${isHistology ? 0.44 : 0.32}" stroke-linecap="round"/>`).join("");
  const tissueLobules = [[-29, -12, 22, 15], [5, -16, 25, 17], [27, 7, 20, 14], [-16, 18, 26, 15]].map(([x, y, rx, ry], index) => `<path class="asset-tissue-lobule" d="M${fmt(cx + (x - rx) * s)},${fmt(cy + y * s)} C${fmt(cx + (x - rx * 0.55) * s)},${fmt(cy + (y - ry) * s)} ${fmt(cx + (x + rx * 0.75) * s)},${fmt(cy + (y - ry * 0.8) * s)} ${fmt(cx + (x + rx) * s)},${fmt(cy + (y + 1) * s)} C${fmt(cx + (x + rx * 0.55) * s)},${fmt(cy + (y + ry) * s)} ${fmt(cx + (x - rx * 0.8) * s)},${fmt(cy + (y + ry * 0.65) * s)} ${fmt(cx + (x - rx) * s)},${fmt(cy + y * s)} Z" fill="${index % 2 ? palette.secondary : "#ffffff"}" stroke="${palette.accent}" stroke-width="${fmt(1.05 * s)}" opacity="${isHistology ? 0.42 : 0.34}"/>`).join("");
  const nuclei = Array.from({ length: isHistology ? 34 : 20 }, (_, i) => {
    const a = i * 2.279;
    const r = (6 + (i % 8) * 4.8) * s;
    const px = cx + Math.cos(a) * r;
    const py = cy + Math.sin(a) * r * 0.66;
    const rotate = (i * 37) % 180;
    return `<ellipse class="asset-tissue-nucleus" cx="${fmt(px)}" cy="${fmt(py)}" rx="${fmt((isHistology ? 2.45 : 2.1) * s)}" ry="${fmt((isHistology ? 1.45 : 1.25) * s)}" fill="${palette.accent}" opacity="${isHistology ? 0.72 : 0.56}" transform="rotate(${rotate} ${fmt(px)} ${fmt(py)})"/>`;
  }).join("");
  const glands = isHistology ? [[-22, -5], [13, 11], [30, -12]].map(([x, y], index) => `<g class="asset-tissue-gland"><ellipse cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" rx="${fmt((index === 1 ? 13 : 10) * s)}" ry="${fmt((index === 1 ? 8 : 7) * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.35 * s)}" opacity="0.72"/><ellipse cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" rx="${fmt((index === 1 ? 6 : 4.7) * s)}" ry="${fmt((index === 1 ? 3.4 : 2.9) * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(0.8 * s)}" opacity="0.82"/></g>`).join("") : "";
  const capillaries = `<path class="asset-tissue-capillary" d="M${fmt(cx - 45 * s)},${fmt(cy + 13 * s)} C${fmt(cx - 24 * s)},${fmt(cy - 3 * s)} ${fmt(cx + 3 * s)},${fmt(cy + 24 * s)} ${fmt(cx + 41 * s)},${fmt(cy + 4 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt((isHistology ? 1.7 : 1.25) * s)}" opacity="${isHistology ? 0.45 : 0.28}" stroke-linecap="round"/><circle cx="${fmt(cx - 40 * s)}" cy="${fmt(cy + 11 * s)}" r="${fmt(3 * s)}" fill="${palette.stroke}" opacity="0.34"/><circle cx="${fmt(cx + 38 * s)}" cy="${fmt(cy + 5 * s)}" r="${fmt(2.8 * s)}" fill="${palette.stroke}" opacity="0.28"/>`;
  const sectionLayers = isSection ? `<path d="M${fmt(cx - 47 * s)},${fmt(cy - 8 * s)} C${fmt(cx - 17 * s)},${fmt(cy - 19 * s)} ${fmt(cx + 17 * s)},${fmt(cy - 14 * s)} ${fmt(cx + 45 * s)},${fmt(cy - 3 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.2 * s)}" opacity="0.62" stroke-linecap="round"/><path d="M${fmt(cx - 43 * s)},${fmt(cy + 9 * s)} C${fmt(cx - 16 * s)},${fmt(cy - 1 * s)} ${fmt(cx + 19 * s)},${fmt(cy + 5 * s)} ${fmt(cx + 41 * s)},${fmt(cy + 15 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(2 * s)}" opacity="0.58" stroke-linecap="round"/><path d="M${fmt(cx - 42 * s)},${fmt(cy + 25 * s)} C${fmt(cx - 13 * s)},${fmt(cy + 34 * s)} ${fmt(cx + 22 * s)},${fmt(cy + 29 * s)} ${fmt(cx + 44 * s)},${fmt(cy + 16 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(1.25 * s)}" opacity="0.32" stroke-linecap="round"/>` : "";
  const region = isRegion ? `<g class="asset-tissue-region"><path d="M${fmt(cx - 22 * s)},${fmt(cy - 21 * s)} C${fmt(cx + 2 * s)},${fmt(cy - 36 * s)} ${fmt(cx + 31 * s)},${fmt(cy - 13 * s)} ${fmt(cx + 26 * s)},${fmt(cy + 12 * s)} C${fmt(cx + 14 * s)},${fmt(cy + 33 * s)} ${fmt(cx - 27 * s)},${fmt(cy + 29 * s)} ${fmt(cx - 34 * s)},${fmt(cy + 4 * s)} C${fmt(cx - 38 * s)},${fmt(cy - 9 * s)} ${fmt(cx - 32 * s)},${fmt(cy - 16 * s)} ${fmt(cx - 22 * s)},${fmt(cy - 21 * s)} Z" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.9 * s)}" opacity="0.74"/><path d="M${fmt(cx - 27 * s)},${fmt(cy - 2 * s)} C${fmt(cx - 7 * s)},${fmt(cy - 14 * s)} ${fmt(cx + 12 * s)},${fmt(cy + 7 * s)} ${fmt(cx + 27 * s)},${fmt(cy - 5 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.6 * s)}" opacity="0.56" stroke-linecap="round"/></g>` : "";
  const slideEdge = `<path d="M${fmt(cx - 50 * s)},${fmt(cy + 35 * s)} C${fmt(cx - 18 * s)},${fmt(cy + 49 * s)} ${fmt(cx + 23 * s)},${fmt(cy + 45 * s)} ${fmt(cx + 50 * s)},${fmt(cy + 27 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.6 * s)}" opacity="0.36" stroke-linecap="round"/>`;
  return `${baseLayer(cx, cy, s, palette)}<g filter="url(#asset-soft-shadow)">${capsule}${sectionLayers}${tissueLobules}${stromalFibers}${capillaries}${glands}${region}${nuclei}${slideEdge}</g>`;
}

function helixAsset(cx, cy, s, palette, kind) {
  const isRna = kind === "rna";
  const rungs = [-29, -18, -7, 4, 15, 26].map((offset, index) => `<path d="M${fmt(cx - (isRna ? 20 : 32) * s)},${fmt(cy + offset * s)} H${fmt(cx + (isRna ? 20 : 32) * s)}" stroke="${index % 2 ? palette.stroke : palette.accent}" stroke-width="${fmt(2.2 * s)}" stroke-linecap="round" opacity="0.72"/>`).join("");
  const extra = isRna ? `<circle cx="${fmt(cx + 34 * s)}" cy="${fmt(cy - 29 * s)}" r="${fmt(7 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(2 * s)}"/><text x="${fmt(cx + 34 * s)}" y="${fmt(cy - 26 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(8 * s)}" font-weight="800" fill="${palette.accent}">U</text>` : "";
  return `${baseLayer(cx, cy, s, palette)}<path d="M${fmt(cx - 39 * s)},${fmt(cy - 37 * s)} C${fmt(cx + 46 * s)},${fmt(cy - 15 * s)} ${fmt(cx - 46 * s)},${fmt(cy + 15 * s)} ${fmt(cx + 39 * s)},${fmt(cy + 37 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(5 * s)}" stroke-linecap="round" filter="url(#asset-soft-shadow)"/><path d="M${fmt(cx + 39 * s)},${fmt(cy - 37 * s)} C${fmt(cx - 46 * s)},${fmt(cy - 15 * s)} ${fmt(cx + 46 * s)},${fmt(cy + 15 * s)} ${fmt(cx - 39 * s)},${fmt(cy + 37 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(isRna ? 3.8 : 5) * s}" stroke-linecap="round"/>${rungs}${extra}${shine(cx - 20 * s, cy - 31 * s, s)}`;
}

function geneTrack(cx, cy, s, palette) {
  const panel = `<rect class="asset-gene-locus-frame" x="${fmt(cx - 50 * s)}" y="${fmt(cy - 34 * s)}" width="${fmt(100 * s)}" height="${fmt(68 * s)}" rx="${fmt(15 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.1 * s)}"/><rect class="asset-gene-track-ruler" x="${fmt(cx - 46 * s)}" y="${fmt(cy - 30 * s)}" width="${fmt(92 * s)}" height="${fmt(18 * s)}" rx="${fmt(9 * s)}" fill="#ffffff" opacity="0.56"/><path class="asset-gene-track-axis" d="M${fmt(cx - 40 * s)},${fmt(cy - 20 * s)} H${fmt(cx + 37 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(1.2 * s)}" opacity="0.42" stroke-linecap="round"/>`;
  const ticks = [-35, -20, -5, 10, 25, 40].map((x, index) => `<path class="asset-gene-track-tick" d="M${fmt(cx + x * s)},${fmt(cy - 24 * s)} v${fmt((index % 2 ? 7 : 10) * s)}" stroke="${palette.stroke}" stroke-width="${fmt(0.9 * s)}" opacity="0.42" stroke-linecap="round"/>`).join("");
  const geneLine = `<path class="asset-gene-track-axis" d="M${fmt(cx - 38 * s)},${fmt(cy + 5 * s)} H${fmt(cx + 42 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(2.3 * s)}" stroke-linecap="round"/>`;
  const exons = [[-31, 17, palette.accent], [-7, 13, palette.secondary], [13, 25, palette.accent], [43, 9, palette.secondary]].map(([x, w, fill], index) => `<rect class="asset-gene-exon" x="${fmt(cx + x * s)}" y="${fmt(cy - (index === 2 ? 8 : 6) * s)}" width="${fmt(w * s)}" height="${fmt((index === 2 ? 16 : 12) * s)}" rx="${fmt(4 * s)}" fill="${fill}" stroke="${palette.accent}" stroke-width="${fmt(1.25 * s)}" opacity="${index % 2 ? 0.92 : 1}"/>`).join("");
  const arrows = [-17, 4, 31].map((x) => `<path class="asset-gene-direction-arrow" d="M${fmt(cx + x * s)},${fmt(cy + 5 * s)} l${fmt(6 * s)},${fmt(-4 * s)} l0,${fmt(8 * s)} Z" fill="${palette.stroke}" opacity="0.55"/>`).join("");
  const geneLabel = palette.styleProfile === "publication-line"
    ? `<text class="asset-gene-locus-label" x="${fmt(cx - 31 * s)}" y="${fmt(cy - 21.7 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(6.7 * s)}" font-weight="900" fill="${palette.accent}">GENE</text>`
    : `<rect class="asset-gene-locus-label-box" x="${fmt(cx - 44 * s)}" y="${fmt(cy - 31 * s)}" width="${fmt(26 * s)}" height="${fmt(13 * s)}" rx="${fmt(6.5 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.15 * s)}"/><text class="asset-gene-locus-label" x="${fmt(cx - 31 * s)}" y="${fmt(cy - 21.7 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(6.7 * s)}" font-weight="900" fill="${palette.accent}">GENE</text>`;
  const regulatory = `<path class="asset-regulatory-loop" d="M${fmt(cx - 35 * s)},${fmt(cy + 19 * s)} C${fmt(cx - 20 * s)},${fmt(cy + 35 * s)} ${fmt(cx + 18 * s)},${fmt(cy + 35 * s)} ${fmt(cx + 33 * s)},${fmt(cy + 17 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.9 * s)}" stroke-linecap="round" opacity="0.72"/><circle cx="${fmt(cx - 36 * s)}" cy="${fmt(cy + 19 * s)}" r="${fmt(5.2 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.3 * s)}"/><circle cx="${fmt(cx + 34 * s)}" cy="${fmt(cy + 17 * s)}" r="${fmt(5.2 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.3 * s)}"/>${geneLabel}`;
  const signal = `<path class="asset-gene-locus-signal" d="M${fmt(cx - 36 * s)},${fmt(cy + 27 * s)} h${fmt(15 * s)} M${fmt(cx - 13 * s)},${fmt(cy + 27 * s)} h${fmt(22 * s)} M${fmt(cx + 17 * s)},${fmt(cy + 27 * s)} h${fmt(20 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.8 * s)}" stroke-linecap="round" opacity="0.5"/>`;
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-gene-locus" filter="url(#asset-soft-shadow)">${panel}${ticks}${geneLine}${exons}${arrows}${regulatory}${signal}<path class="asset-gene-locus-rim-highlight" d="M${fmt(cx - 38 * s)},${fmt(cy - 29 * s)} C${fmt(cx - 11 * s)},${fmt(cy - 39 * s)} ${fmt(cx + 24 * s)},${fmt(cy - 37 * s)} ${fmt(cx + 43 * s)},${fmt(cy - 25 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.8 * s)}" opacity="0.54" stroke-linecap="round"/></g>`;
}

function umiTagAsset(cx, cy, s, palette) {
  const beads = [-27, -12, 3, 18, 33].map((x, index) => `<rect class="asset-umi-barcode-bead ${index === 2 ? "asset-umi-center-base" : ""}" data-umi-base-index="${index}" x="${fmt(cx + x * s - 7 * s)}" y="${fmt(cy - 8 * s)}" width="${fmt(14 * s)}" height="${fmt(16 * s)}" rx="${fmt(5 * s)}" fill="${index === 2 ? palette.accent : palette.secondary}" opacity="${index === 2 ? 0.92 : 1}" stroke="${palette.accent}" stroke-width="${fmt(1.5 * s)}"/>`).join("");
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-umi-tag asset-umi-tag-body" filter="url(#asset-soft-shadow)"><path class="asset-umi-linker" d="M${fmt(cx - 45 * s)},${fmt(cy)} H${fmt(cx + 45 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(3 * s)}" stroke-linecap="round"/>${beads}<path class="asset-umi-capture-hairpin" d="M${fmt(cx - 37 * s)},${fmt(cy - 25 * s)} h${fmt(32 * s)} q${fmt(9 * s)},0 ${fmt(9 * s)},${fmt(9 * s)} v${fmt(8 * s)} M${fmt(cx - 21 * s)},${fmt(cy - 24 * s)} v${fmt(16 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2 * s)}" stroke-linecap="round"/><rect class="asset-umi-capture-window" x="${fmt(cx - 46 * s)}" y="${fmt(cy - 40 * s)}" width="${fmt(42 * s)}" height="${fmt(20 * s)}" rx="${fmt(8 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.6 * s)}"/><path class="asset-umi-capture-read" d="M${fmt(cx - 38 * s)},${fmt(cy - 30 * s)} h${fmt(25 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.7 * s)}" stroke-linecap="round"/><circle class="asset-umi-status-dot asset-umi-tag-anchor" cx="${fmt(cx + 45 * s)}" cy="${fmt(cy + 24 * s)}" r="${fmt(6 * s)}" fill="${palette.accent}"/></g>`;
}

function readPairAsset(cx, cy, s, palette) {
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-read-pair asset-read-pair-alignment" filter="url(#asset-soft-shadow)"><rect class="asset-read-pair-forward-read" x="${fmt(cx - 47 * s)}" y="${fmt(cy - 30 * s)}" width="${fmt(70 * s)}" height="${fmt(18 * s)}" rx="${fmt(7 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(1.8 * s)}"/><rect class="asset-read-pair-reverse-read" x="${fmt(cx - 23 * s)}" y="${fmt(cy + 12 * s)}" width="${fmt(70 * s)}" height="${fmt(18 * s)}" rx="${fmt(7 * s)}" fill="${palette.secondary}" stroke="${palette.stroke}" stroke-width="${fmt(1.8 * s)}"/><path class="asset-read-pair-direction-arrows asset-read-pair-insert-orientation" d="M${fmt(cx + 13 * s)},${fmt(cy - 21 * s)} h${fmt(22 * s)} M${fmt(cx + 25 * s)},${fmt(cy - 29 * s)} l${fmt(10 * s)},${fmt(8 * s)} l${fmt(-10 * s)},${fmt(8 * s)} M${fmt(cx - 13 * s)},${fmt(cy + 21 * s)} h${fmt(-22 * s)} M${fmt(cx - 25 * s)},${fmt(cy + 13 * s)} l${fmt(-10 * s)},${fmt(8 * s)} l${fmt(10 * s)},${fmt(8 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.4 * s)}" stroke-linecap="round" stroke-linejoin="round"/><path class="asset-read-pair-base-ticks" d="M${fmt(cx - 33 * s)},${fmt(cy - 21 * s)} h${fmt(16 * s)} M${fmt(cx - 3 * s)},${fmt(cy - 21 * s)} h${fmt(15 * s)} M${fmt(cx - 8 * s)},${fmt(cy + 21 * s)} h${fmt(17 * s)} M${fmt(cx + 20 * s)},${fmt(cy + 21 * s)} h${fmt(15 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.6 * s)}" stroke-linecap="round"/><path class="asset-read-pair-insert-arc asset-read-pair-fragment-link" d="M${fmt(cx - 34 * s)},${fmt(cy - 2 * s)} C${fmt(cx - 17 * s)},${fmt(cy + 4 * s)} ${fmt(cx + 15 * s)},${fmt(cy - 6 * s)} ${fmt(cx + 35 * s)},${fmt(cy + 2 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.7 * s)}" stroke-dasharray="${fmt(4 * s)} ${fmt(4 * s)}" opacity="0.76"/></g>`;
}

function peakCallAsset(cx, cy, s, palette) {
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-peak-call asset-atac-peak-call" filter="url(#asset-soft-shadow)"><rect class="asset-peak-call-panel" x="${fmt(cx - 48 * s)}" y="${fmt(cy - 34 * s)}" width="${fmt(96 * s)}" height="${fmt(68 * s)}" rx="${fmt(14 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2 * s)}"/><path class="asset-peak-call-axis" d="M${fmt(cx - 36 * s)},${fmt(cy + 21 * s)} H${fmt(cx + 39 * s)} M${fmt(cx - 36 * s)},${fmt(cy + 21 * s)} V${fmt(cy - 25 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(1.5 * s)}" opacity="0.58"/><path class="asset-peak-call-signal-track asset-peak-call-coverage-curve" d="M${fmt(cx - 32 * s)},${fmt(cy + 19 * s)} C${fmt(cx - 23 * s)},${fmt(cy + 12 * s)} ${fmt(cx - 17 * s)},${fmt(cy - 18 * s)} ${fmt(cx - 8 * s)},${fmt(cy - 18 * s)} C${fmt(cx + 1 * s)},${fmt(cy - 18 * s)} ${fmt(cx + 6 * s)},${fmt(cy + 16 * s)} ${fmt(cx + 15 * s)},${fmt(cy + 17 * s)} C${fmt(cx + 22 * s)},${fmt(cy + 18 * s)} ${fmt(cx + 26 * s)},${fmt(cy - 5 * s)} ${fmt(cx + 35 * s)},${fmt(cy + 9 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(3.2 * s)}" stroke-linecap="round"/><path class="asset-peak-call-boundary asset-peak-call-summit-window" d="M${fmt(cx - 12 * s)},${fmt(cy - 26 * s)} v${fmt(50 * s)} M${fmt(cx + 17 * s)},${fmt(cy - 12 * s)} v${fmt(36 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.7 * s)}" stroke-dasharray="${fmt(4 * s)} ${fmt(4 * s)}" opacity="0.72"/><rect class="asset-peak-call-annotation-badge" x="${fmt(cx + 22 * s)}" y="${fmt(cy - 28 * s)}" width="${fmt(18 * s)}" height="${fmt(16 * s)}" rx="${fmt(5 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.5 * s)}"/></g>`;
}

function genomeBrowserTrackAsset(cx, cy, s, palette) {
  const tracks = [-18, -2, 14].map((y, index) => `<rect class="asset-genome-browser-track-lane ${index === 1 ? "asset-genome-browser-active-coverage" : "asset-genome-browser-reference-track"}" data-track-lane="${index + 1}" x="${fmt(cx - 35 * s)}" y="${fmt(cy + y * s)}" width="${fmt((index === 1 ? 70 : 58) * s)}" height="${fmt(8 * s)}" rx="${fmt(4 * s)}" fill="${index === 1 ? palette.accent : palette.secondary}" opacity="${index === 1 ? 0.88 : 1}" stroke="${palette.accent}" stroke-width="${fmt(1.2 * s)}"/>`).join("");
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-genome-browser-track asset-genome-browser-window" filter="url(#asset-soft-shadow)"><rect class="asset-genome-browser-frame" x="${fmt(cx - 49 * s)}" y="${fmt(cy - 35 * s)}" width="${fmt(98 * s)}" height="${fmt(70 * s)}" rx="${fmt(13 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2 * s)}"/><path class="asset-genome-browser-ruler" d="M${fmt(cx - 36 * s)},${fmt(cy - 25 * s)} h${fmt(72 * s)} M${fmt(cx - 36 * s)},${fmt(cy + 27 * s)} h${fmt(72 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(1.4 * s)}" opacity="0.45" stroke-linecap="round"/>${tracks}<path class="asset-genome-browser-coordinate-ticks" d="M${fmt(cx - 31 * s)},${fmt(cy - 26 * s)} v${fmt(56 * s)} M${fmt(cx + 2 * s)},${fmt(cy - 26 * s)} v${fmt(56 * s)} M${fmt(cx + 33 * s)},${fmt(cy - 26 * s)} v${fmt(56 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(1 * s)}" opacity="0.28"/><path class="asset-genome-browser-locus-bracket" d="M${fmt(cx - 40 * s)},${fmt(cy - 30 * s)} l${fmt(8 * s)},${fmt(-8 * s)} h${fmt(64 * s)} l${fmt(8 * s)},${fmt(8 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.8 * s)}" stroke-linecap="round" stroke-linejoin="round"/></g>`;
}

function variantSnpAsset(cx, cy, s, palette) {
  const bases = ["A", "C", "T", "G", "A"].map((base, index) => `<g class="asset-snp-base ${index === 2 ? "asset-snp-variant-base" : "asset-snp-reference-base"}" data-base-index="${index}"><rect x="${fmt(cx + (-40 + index * 20) * s)}" y="${fmt(cy - 10 * s)}" width="${fmt(16 * s)}" height="${fmt(20 * s)}" rx="${fmt(6 * s)}" fill="${index === 2 ? palette.accent : palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.5 * s)}"/><text x="${fmt(cx + (-32 + index * 20) * s)}" y="${fmt(cy + 3 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(10 * s)}" font-weight="800" fill="${index === 2 ? "#ffffff" : palette.accent}">${base}</text></g>`).join("");
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-variant-snp asset-snp-variant-call" filter="url(#asset-soft-shadow)"><path class="asset-snp-dna-backbone" d="M${fmt(cx - 46 * s)},${fmt(cy)} H${fmt(cx + 49 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(2.5 * s)}" stroke-linecap="round"/>${bases}<circle class="asset-snp-callout-bubble" cx="${fmt(cx + 8 * s)}" cy="${fmt(cy - 27 * s)}" r="${fmt(13 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(2 * s)}"/><path class="asset-snp-callout-stem" d="M${fmt(cx + 8 * s)},${fmt(cy - 35 * s)} v${fmt(11 * s)}" stroke="${palette.accent}" stroke-width="${fmt(2.2 * s)}" stroke-linecap="round"/><circle class="asset-snp-quality-dot" cx="${fmt(cx + 8 * s)}" cy="${fmt(cy - 19 * s)}" r="${fmt(2.2 * s)}" fill="${palette.accent}"/><path class="asset-snp-locus-anchor" d="M${fmt(cx + 8 * s)},${fmt(cy - 13 * s)} v${fmt(8 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.7 * s)}" stroke-linecap="round"/></g>`;
}

function copyNumberAsset(cx, cy, s, palette) {
  const bars = [[-34, 20], [-20, 20], [-6, 31], [8, 31], [22, 13], [36, 13]].map(([x, h], index) => `<rect class="asset-copy-number-segment ${index === 2 || index === 3 ? "asset-copy-number-gain-segment" : "asset-copy-number-neutral-segment"}" data-copy-number-bin="${index}" x="${fmt(cx + x * s)}" y="${fmt(cy + (22 - h) * s)}" width="${fmt(10 * s)}" height="${fmt(h * s)}" rx="${fmt(4 * s)}" fill="${index === 2 || index === 3 ? palette.accent : palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.2 * s)}" opacity="${index > 3 ? 0.72 : 1}"/>`).join("");
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-copy-number asset-copy-number-profile" filter="url(#asset-soft-shadow)"><rect class="asset-copy-number-frame" x="${fmt(cx - 48 * s)}" y="${fmt(cy - 34 * s)}" width="${fmt(96 * s)}" height="${fmt(68 * s)}" rx="${fmt(14 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2 * s)}"/><path class="asset-copy-number-baseline-grid" d="M${fmt(cx - 37 * s)},${fmt(cy + 22 * s)} H${fmt(cx + 47 * s)} M${fmt(cx - 37 * s)},${fmt(cy + 3 * s)} H${fmt(cx + 47 * s)} M${fmt(cx - 37 * s)},${fmt(cy - 16 * s)} H${fmt(cx + 47 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(1.2 * s)}" opacity="0.24"/>${bars}<path class="asset-copy-number-chromosome-arm" d="M${fmt(cx - 28 * s)},${fmt(cy - 28 * s)} h${fmt(30 * s)} M${fmt(cx + 10 * s)},${fmt(cy - 28 * s)} h${fmt(27 * s)}" stroke="${palette.accent}" stroke-width="${fmt(2 * s)}" stroke-linecap="round"/><path class="asset-copy-number-breakpoint-marker" d="M${fmt(cx - 10 * s)},${fmt(cy - 31 * s)} l${fmt(8 * s)},${fmt(8 * s)} l${fmt(8 * s)},${fmt(-8 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2 * s)}" stroke-linecap="round" stroke-linejoin="round"/></g>`;
}

function chromatinAsset(cx, cy, s, palette) {
  const fiber = `M${fmt(cx - 52 * s)},${fmt(cy + 10 * s)} C${fmt(cx - 37 * s)},${fmt(cy - 27 * s)} ${fmt(cx - 12 * s)},${fmt(cy - 31 * s)} ${fmt(cx + 2 * s)},${fmt(cy - 8 * s)} C${fmt(cx + 18 * s)},${fmt(cy + 19 * s)} ${fmt(cx + 36 * s)},${fmt(cy + 22 * s)} ${fmt(cx + 51 * s)},${fmt(cy - 14 * s)}`;
  const nucleosomePositions = [[-40, 3, 10.5], [-24, -16, 9.5], [-4, -6, 11.2], [15, 13, 10], [34, -3, 11], [47, -21, 8.3]];
  const beads = nucleosomePositions.map(([x, y, r], index) => {
    const px = cx + x * s;
    const py = cy + y * s;
    const fill = index % 2 ? palette.secondary : palette.fill;
    const mark = index === 1 || index === 4 ? `<circle class="asset-chromatin-histone-mark" cx="${fmt(px + r * 0.35 * s)}" cy="${fmt(py - r * 0.42 * s)}" r="${fmt(2.5 * s)}" fill="${palette.accent}" opacity="0.82"/>` : "";
    return `<g class="asset-chromatin-nucleosome" data-nucleosome-index="${index}"><circle class="asset-chromatin-nucleosome-core" cx="${fmt(px)}" cy="${fmt(py)}" r="${fmt(r * s)}" fill="${fill}" stroke="${palette.stroke}" stroke-width="${fmt(1.55 * s)}"/><path class="asset-chromatin-nucleosome-rim" d="M${fmt(px - r * 0.55 * s)},${fmt(py - r * 0.35 * s)} C${fmt(px - r * 0.12 * s)},${fmt(py - r * 0.78 * s)} ${fmt(px + r * 0.52 * s)},${fmt(py - r * 0.5 * s)} ${fmt(px + r * 0.64 * s)},${fmt(py + r * 0.06 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.25 * s)}" opacity="0.58" stroke-linecap="round"/>${mark}</g>`;
  }).join("");
  const loop = `<path class="asset-chromatin-loop" d="M${fmt(cx - 31 * s)},${fmt(cy + 14 * s)} C${fmt(cx - 17 * s)},${fmt(cy + 45 * s)} ${fmt(cx + 22 * s)},${fmt(cy + 44 * s)} ${fmt(cx + 37 * s)},${fmt(cy + 13 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(2 * s)}" stroke-linecap="round" opacity="0.48"/><path d="M${fmt(cx - 28 * s)},${fmt(cy + 15 * s)} C${fmt(cx - 6 * s)},${fmt(cy + 29 * s)} ${fmt(cx + 14 * s)},${fmt(cy + 29 * s)} ${fmt(cx + 34 * s)},${fmt(cy + 12 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.3 * s)}" opacity="0.52" stroke-linecap="round"/>`;
  const methylMarks = [[-42, -20], [-11, 17], [25, -26], [41, 16]].map(([x, y], index) => `<rect class="asset-chromatin-methyl-mark asset-chromatin-epigenetic-mark" data-epigenetic-mark="${index}" x="${fmt(cx + x * s)}" y="${fmt(cy + y * s)}" width="${fmt(9 * s)}" height="${fmt(7 * s)}" rx="${fmt(3.5 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}" opacity="0.9"/>`).join("");
  return `${baseLayer(cx, cy, s, palette)}<g class="asset-chromatin asset-chromatin-fiber" filter="url(#asset-soft-shadow)">${loop}<path class="asset-chromatin-backbone" d="${fiber}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(5.4 * s)}" stroke-linecap="round" opacity="0.72"/><path class="asset-chromatin-accessibility-track" d="${fiber}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.3 * s)}" stroke-linecap="round" opacity="0.92"/>${beads}${methylMarks}</g>`;
}

function nucleosomeAsset(cx, cy, s, palette) {
  const histones = [];
  for (let i = 0; i < 8; i += 1) {
    const a = (Math.PI * 2 * i) / 8 - Math.PI / 8;
    const px = cx + Math.cos(a) * 14 * s;
    const py = cy + Math.sin(a) * 11 * s;
    histones.push(`<g class="asset-histone-lobe asset-nucleosome-histone-octamer" data-histone-index="${i}"><circle class="asset-nucleosome-histone-core" cx="${fmt(px)}" cy="${fmt(py)}" r="${fmt(10.4 * s)}" fill="${i % 2 ? palette.secondary : palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(1.35 * s)}"/><circle class="asset-nucleosome-histone-highlight" cx="${fmt(px - 2.5 * s)}" cy="${fmt(py - 3 * s)}" r="${fmt(3.1 * s)}" fill="#ffffff" opacity="0.42"/></g>`);
  }
  const backDna = `<path class="asset-nucleosome-dna-back" d="M${fmt(cx - 54 * s)},${fmt(cy + 10 * s)} C${fmt(cx - 39 * s)},${fmt(cy - 30 * s)} ${fmt(cx - 9 * s)},${fmt(cy - 42 * s)} ${fmt(cx + 19 * s)},${fmt(cy - 26 * s)} C${fmt(cx + 42 * s)},${fmt(cy - 13 * s)} ${fmt(cx + 50 * s)},${fmt(cy + 10 * s)} ${fmt(cx + 29 * s)},${fmt(cy + 25 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(5.7 * s)}" stroke-linecap="round" opacity="0.84"/>`;
  const frontDna = `<path class="asset-nucleosome-dna-front" d="M${fmt(cx - 32 * s)},${fmt(cy + 24 * s)} C${fmt(cx - 6 * s)},${fmt(cy + 42 * s)} ${fmt(cx + 34 * s)},${fmt(cy + 31 * s)} ${fmt(cx + 53 * s)},${fmt(cy - 11 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(5.5 * s)}" stroke-linecap="round"/><path d="M${fmt(cx - 50 * s)},${fmt(cy + 10 * s)} C${fmt(cx - 26 * s)},${fmt(cy - 8 * s)} ${fmt(cx - 8 * s)},${fmt(cy - 24 * s)} ${fmt(cx + 18 * s)},${fmt(cy - 26 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.4 * s)}" stroke-linecap="round" opacity="0.9"/>`;
  const rungs = [-43, -30, -16, 8, 25, 41].map((x, index) => `<path class="asset-nucleosome-dna-rung" data-rung-index="${index}" d="M${fmt(cx + x * s)},${fmt(cy + (index % 2 ? -2 : 3) * s)} l${fmt((index % 2 ? 5 : -5) * s)},${fmt((index % 2 ? -11 : 11) * s)}" stroke="#ffffff" stroke-width="${fmt(1.45 * s)}" opacity="0.68" stroke-linecap="round"/>`).join("");
  const core = `<g class="asset-nucleosome-core"><ellipse cx="${fmt(cx)}" cy="${fmt(cy + 1.5 * s)}" rx="${fmt(30 * s)}" ry="${fmt(24 * s)}" fill="${palette.secondary}" opacity="0.28"/>${histones.join("")}<circle cx="${fmt(cx)}" cy="${fmt(cy)}" r="${fmt(9.5 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.55 * s)}" opacity="0.94"/><path d="M${fmt(cx - 16 * s)},${fmt(cy - 17 * s)} C${fmt(cx - 4 * s)},${fmt(cy - 24 * s)} ${fmt(cx + 10 * s)},${fmt(cy - 23 * s)} ${fmt(cx + 20 * s)},${fmt(cy - 15 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.7 * s)}" opacity="0.6" stroke-linecap="round"/></g>`;
  const tails = `<path class="asset-nucleosome-histone-tail" d="M${fmt(cx - 25 * s)},${fmt(cy - 10 * s)} c${fmt(-18 * s)},${fmt(-8 * s)} ${fmt(-24 * s)},${fmt(-1 * s)} ${fmt(-34 * s)},${fmt(-10 * s)} M${fmt(cx + 25 * s)},${fmt(cy + 10 * s)} c${fmt(19 * s)},${fmt(9 * s)} ${fmt(27 * s)},${fmt(0)} ${fmt(36 * s)},${fmt(12 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.8 * s)}" stroke-linecap="round" opacity="0.54"/><circle class="asset-nucleosome-tail-mark" cx="${fmt(cx - 55 * s)}" cy="${fmt(cy - 20 * s)}" r="${fmt(3 * s)}" fill="${palette.accent}" opacity="0.8"/><circle class="asset-nucleosome-tail-mark" cx="${fmt(cx + 61 * s)}" cy="${fmt(cy + 22 * s)}" r="${fmt(3 * s)}" fill="${palette.accent}" opacity="0.8"/>`;
  return `${baseLayer(cx, cy, s, palette)}<g class="asset-nucleosome asset-nucleosome-wrapped-dna" filter="url(#asset-soft-shadow)">${backDna}${core}${frontDna}${rungs}${tails}</g>`;
}

function dropletAsset(cx, cy, s, palette) {
  const droplet = `M${fmt(cx)},${fmt(cy - 47 * s)} C${fmt(cx + 33 * s)},${fmt(cy - 13 * s)} ${fmt(cx + 43 * s)},${fmt(cy + 17 * s)} ${fmt(cx + 21 * s)},${fmt(cy + 37 * s)} C${fmt(cx + 2 * s)},${fmt(cy + 55 * s)} ${fmt(cx - 34 * s)},${fmt(cy + 42 * s)} ${fmt(cx - 39 * s)},${fmt(cy + 14 * s)} C${fmt(cx - 43 * s)},${fmt(cy - 10 * s)} ${fmt(cx - 22 * s)},${fmt(cy - 29 * s)} ${fmt(cx)},${fmt(cy - 47 * s)} Z`;
  const rim = `<path class="asset-scrna-oil-rim asset-rim-highlight" d="${droplet}" fill="none" stroke="#ffffff" stroke-width="${fmt(2.1 * s)}" opacity="0.56"/>`;
  const cellBody = `M${fmt(cx - 26 * s)},${fmt(cy - 1 * s)} C${fmt(cx - 20 * s)},${fmt(cy - 16 * s)} ${fmt(cx - 3 * s)},${fmt(cy - 21 * s)} ${fmt(cx + 10 * s)},${fmt(cy - 11 * s)} C${fmt(cx + 23 * s)},${fmt(cy - 1 * s)} ${fmt(cx + 19 * s)},${fmt(cy + 18 * s)} ${fmt(cx + 2 * s)},${fmt(cy + 24 * s)} C${fmt(cx - 17 * s)},${fmt(cy + 31 * s)} ${fmt(cx - 34 * s)},${fmt(cy + 17 * s)} ${fmt(cx - 26 * s)},${fmt(cy - 1 * s)} Z`;
  const cell = `<g class="asset-scrna-cell"><path d="${cellBody}" fill="${palette.secondary}" stroke="${palette.stroke}" stroke-width="${fmt(1.55 * s)}"/><path d="${cellBody}" fill="url(#asset-glass-highlight)" opacity="0.26"/><ellipse class="asset-scrna-nucleus" cx="${fmt(cx - 8 * s)}" cy="${fmt(cy + 6 * s)}" rx="${fmt(8.2 * s)}" ry="${fmt(6.8 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.15 * s)}"/><circle cx="${fmt(cx + 6 * s)}" cy="${fmt(cy + 14 * s)}" r="${fmt(2.6 * s)}" fill="${palette.accent}" opacity="0.74"/></g>`;
  const bead = `<g class="asset-scrna-barcode-bead"><circle cx="${fmt(cx + 24 * s)}" cy="${fmt(cy - 12 * s)}" r="${fmt(12 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.5 * s)}"/><circle cx="${fmt(cx + 20 * s)}" cy="${fmt(cy - 15 * s)}" r="${fmt(2.2 * s)}" fill="${palette.accent}" opacity="0.8"/><circle cx="${fmt(cx + 28 * s)}" cy="${fmt(cy - 9 * s)}" r="${fmt(2.2 * s)}" fill="${palette.accent}" opacity="0.58"/></g>`;
  const umiTags = [-18, -7, 4, 15].map((y, index) => `<path class="asset-scrna-umi-tag" d="M${fmt(cx + 13 * s)},${fmt(cy + y * s)} h${fmt((index % 2 ? 28 : 22) * s)}" stroke="${index % 2 ? palette.stroke : palette.accent}" stroke-width="${fmt(1.45 * s)}" stroke-linecap="round" opacity="${index % 2 ? "0.48" : "0.78"}"/>`).join("");
  const barcodeArc = `<path class="asset-scrna-barcode-arc" d="M${fmt(cx + 7 * s)},${fmt(cy + 25 * s)} C${fmt(cx + 20 * s)},${fmt(cy + 38 * s)} ${fmt(cx + 38 * s)},${fmt(cy + 31 * s)} ${fmt(cx + 41 * s)},${fmt(cy + 14 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.9 * s)}" stroke-linecap="round" fill="none"/>`;
  return `${baseLayer(cx, cy, s, palette)}<g filter="url(#asset-soft-shadow)"><path class="asset-scrna-droplet-shell" d="${droplet}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.5 * s)}"/><path class="asset-scrna-glass-highlight" d="${droplet}" fill="url(#asset-glass-highlight)" opacity="0.42"/>${rim}${cell}${bead}${umiTags}${barcodeArc}<circle class="asset-scrna-status-dot" cx="${fmt(cx + 34 * s)}" cy="${fmt(cy - 25 * s)}" r="${fmt(3.6 * s)}" fill="${palette.accent}" opacity="0.84"/></g><path class="asset-scrna-top-highlight asset-inner-highlight" d="M${fmt(cx - 24 * s)},${fmt(cy - 25 * s)} C${fmt(cx - 10 * s)},${fmt(cy - 36 * s)} ${fmt(cx + 6 * s)},${fmt(cy - 36 * s)} ${fmt(cx + 21 * s)},${fmt(cy - 22 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(2.1 * s)}" opacity="0.6" stroke-linecap="round"/>`;
}

function barcodeAsset(cx, cy, s, palette) {
  const bars = [4, 2, 7, 3, 5, 2, 6, 3, 4].map((w, i) => `<rect class="asset-cell-barcode-bar" data-barcode-index="${i}" x="${fmt(cx - 31 * s + i * 8 * s)}" y="${fmt(cy - 19 * s)}" width="${fmt(w * s)}" height="${fmt(38 * s)}" rx="${fmt(1.5 * s)}" fill="${palette.accent}" opacity="${i % 2 ? 0.52 : 0.9}"/>`).join("");
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-cell-barcode" filter="url(#asset-soft-shadow)"><rect class="asset-cell-barcode-frame" x="${fmt(cx - 45 * s)}" y="${fmt(cy - 32 * s)}" width="${fmt(90 * s)}" height="${fmt(64 * s)}" rx="${fmt(14 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.2 * s)}"/><path class="asset-cell-barcode-rim-highlight" d="M${fmt(cx - 36 * s)},${fmt(cy - 26 * s)} h${fmt(72 * s)}" stroke="#ffffff" stroke-width="${fmt(2 * s)}" opacity="0.58"/><rect class="asset-cell-barcode-read-window" x="${fmt(cx - 35 * s)}" y="${fmt(cy - 22 * s)}" width="${fmt(72 * s)}" height="${fmt(44 * s)}" rx="${fmt(8 * s)}" fill="#ffffff" opacity="0.35" stroke="${palette.accent}" stroke-width="${fmt(1 * s)}"/>${bars}<circle class="asset-cell-barcode-anchor-dot" cx="${fmt(cx + 39 * s)}" cy="${fmt(cy + 24 * s)}" r="${fmt(4 * s)}" fill="${palette.accent}" opacity="0.82"/></g>`;
}

function sequencingRead(cx, cy, s, palette) {
  const bases = "ACGTACGT".split("").map((base, i) => `<text class="asset-sequencing-read-base" data-base-index="${i}" x="${fmt(cx - 36 * s + i * 10 * s)}" y="${fmt(cy - 6 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(8 * s)}" font-weight="800" fill="${i % 2 ? palette.stroke : palette.accent}">${base}</text>`).join("");
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-sequencing-read" filter="url(#asset-soft-shadow)"><rect class="asset-sequencing-read-frame" x="${fmt(cx - 48 * s)}" y="${fmt(cy - 24 * s)}" width="${fmt(96 * s)}" height="${fmt(23 * s)}" rx="${fmt(8 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2 * s)}"/><rect class="asset-sequencing-quality-track" x="${fmt(cx - 35 * s)}" y="${fmt(cy + 10 * s)}" width="${fmt(70 * s)}" height="${fmt(17 * s)}" rx="${fmt(7 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.7 * s)}"/><path class="asset-sequencing-read-adapter" d="M${fmt(cx - 43 * s)},${fmt(cy - 13 * s)} h${fmt(16 * s)} M${fmt(cx + 27 * s)},${fmt(cy + 18 * s)} h${fmt(12 * s)}" stroke="${palette.accent}" stroke-width="${fmt(2 * s)}" stroke-linecap="round"/>${bases}<path class="asset-sequencing-quality-sparkline" d="M${fmt(cx - 30 * s)},${fmt(cy + 18 * s)} C${fmt(cx - 14 * s)},${fmt(cy + 10 * s)} ${fmt(cx + 3 * s)},${fmt(cy + 22 * s)} ${fmt(cx + 30 * s)},${fmt(cy + 13 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.3 * s)}" opacity="0.65" stroke-linecap="round"/></g>`;
}

function matrixAsset(cx, cy, s, palette) {
  const cells = [];
  for (let row = 0; row < 7; row += 1) {
    for (let col = 0; col < 8; col += 1) {
      const signal = (row * 5 + col * 3 + (row > 3 && col > 4 ? 3 : 0)) % 9;
      const active = signal > 4;
      cells.push(`<rect class="asset-expression-matrix-cell${active ? " asset-expression-matrix-hit" : ""}" data-row="${row}" data-col="${col}" x="${fmt(cx - 35 * s + col * 9.3 * s)}" y="${fmt(cy - 24 * s + row * 7.6 * s)}" width="${fmt(7.2 * s)}" height="${fmt(5.8 * s)}" rx="${fmt(1.45 * s)}" fill="${active ? palette.accent : palette.secondary}" opacity="${active ? 0.88 : 0.48}"/>`);
    }
  }
  const dendrogram = `<path class="asset-expression-matrix-dendrogram" d="M${fmt(cx - 41 * s)},${fmt(cy - 38 * s)} v${fmt(8 * s)} h${fmt(16 * s)} v${fmt(-8 * s)} M${fmt(cx - 25 * s)},${fmt(cy - 34 * s)} h${fmt(18 * s)} M${fmt(cx + 2 * s)},${fmt(cy - 38 * s)} v${fmt(8 * s)} h${fmt(21 * s)} v${fmt(-8 * s)} M${fmt(cx + 23 * s)},${fmt(cy - 34 * s)} h${fmt(16 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.35 * s)}" stroke-linecap="round" opacity="0.78"/>`;
  const axes = `<path class="asset-expression-matrix-axis" d="M${fmt(cx - 41 * s)},${fmt(cy + 33 * s)} h${fmt(78 * s)} M${fmt(cx - 41 * s)},${fmt(cy + 33 * s)} v${fmt(-55 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(1.15 * s)}" stroke-linecap="round" opacity="0.5"/><path class="asset-expression-matrix-cluster-band" d="M${fmt(cx + 10 * s)},${fmt(cy - 27 * s)} v${fmt(54 * s)} M${fmt(cx + 31 * s)},${fmt(cy - 27 * s)} v${fmt(54 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.25 * s)}" opacity="0.34"/>`;
  const sideLabels = `<g class="asset-expression-matrix-labels"><rect x="${fmt(cx - 49 * s)}" y="${fmt(cy - 20 * s)}" width="${fmt(7 * s)}" height="${fmt(13 * s)}" rx="${fmt(3.5 * s)}" fill="${palette.accent}" opacity="0.64"/><rect x="${fmt(cx - 49 * s)}" y="${fmt(cy + 4 * s)}" width="${fmt(7 * s)}" height="${fmt(13 * s)}" rx="${fmt(3.5 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(0.8 * s)}"/></g>`;
  return `${baseLayer(cx, cy, s, palette, "panel")}<g filter="url(#asset-soft-shadow)"><rect class="asset-expression-matrix-frame" x="${fmt(cx - 49 * s)}" y="${fmt(cy - 38 * s)}" width="${fmt(98 * s)}" height="${fmt(76 * s)}" rx="${fmt(13 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.1 * s)}"/><path class="asset-expression-matrix-header" d="M${fmt(cx - 41 * s)},${fmt(cy - 29 * s)} h${fmt(80 * s)}" stroke="#ffffff" stroke-width="${fmt(2 * s)}" opacity="0.44" stroke-linecap="round"/><rect class="asset-expression-matrix-grid" x="${fmt(cx - 40 * s)}" y="${fmt(cy - 27 * s)}" width="${fmt(80 * s)}" height="${fmt(60 * s)}" rx="${fmt(7 * s)}" fill="#ffffff" opacity="0.48" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}"/>${cells.join("")}${axes}<path class="asset-expression-matrix-grid-lines" d="M${fmt(cx - 40 * s)},${fmt(cy - 9 * s)} h${fmt(80 * s)} M${fmt(cx - 16 * s)},${fmt(cy - 27 * s)} v${fmt(60 * s)}" stroke="#ffffff" stroke-width="${fmt(1.05 * s)}" opacity="0.5"/>${dendrogram}${sideLabels}</g>`;
}

function crisprAsset(cx, cy, s, palette) {
  const dnaBack = `<path class="asset-crispr-dna-backbone" d="M${fmt(cx - 49 * s)},${fmt(cy + 22 * s)} C${fmt(cx - 20 * s)},${fmt(cy + 4 * s)} ${fmt(cx + 17 * s)},${fmt(cy + 35 * s)} ${fmt(cx + 49 * s)},${fmt(cy + 11 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(5.2 * s)}" stroke-linecap="round"/>`;
  const dnaFront = `<path class="asset-crispr-target-dna" d="M${fmt(cx - 48 * s)},${fmt(cy + 5 * s)} C${fmt(cx - 19 * s)},${fmt(cy + 30 * s)} ${fmt(cx + 17 * s)},${fmt(cy - 2 * s)} ${fmt(cx + 49 * s)},${fmt(cy + 21 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.6 * s)}" stroke-linecap="round" opacity="0.86"/>`;
  const cas9 = `<g class="asset-crispr-cas9-enzyme"><path class="asset-crispr-cas9-body" d="M${fmt(cx - 8 * s)},${fmt(cy - 42 * s)} C${fmt(cx + 28 * s)},${fmt(cy - 50 * s)} ${fmt(cx + 48 * s)},${fmt(cy - 20 * s)} ${fmt(cx + 34 * s)},${fmt(cy + 4 * s)} C${fmt(cx + 18 * s)},${fmt(cy + 31 * s)} ${fmt(cx - 15 * s)},${fmt(cy + 17 * s)} ${fmt(cx - 14 * s)},${fmt(cy - 10 * s)} C${fmt(cx - 27 * s)},${fmt(cy - 21 * s)} ${fmt(cx - 24 * s)},${fmt(cy - 37 * s)} ${fmt(cx - 8 * s)},${fmt(cy - 42 * s)} Z" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.2 * s)}"/><rect class="asset-crispr-cas9-label-window" x="${fmt(cx + 6 * s)}" y="${fmt(cy - 34 * s)}" width="${fmt(38 * s)}" height="${fmt(20 * s)}" rx="${fmt(8 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.5 * s)}"/><text class="asset-crispr-cas9-label" x="${fmt(cx + 25 * s)}" y="${fmt(cy - 20.5 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(9 * s)}" font-weight="900" fill="${palette.accent}">Cas9</text></g>`;
  const grna = `<g class="asset-crispr-guide-rna"><path class="asset-crispr-grna-loop" d="M${fmt(cx - 42 * s)},${fmt(cy - 23 * s)} C${fmt(cx - 23 * s)},${fmt(cy - 45 * s)} ${fmt(cx - 1 * s)},${fmt(cy - 27 * s)} ${fmt(cx - 18 * s)},${fmt(cy - 8 * s)} C${fmt(cx - 30 * s)},${fmt(cy + 5 * s)} ${fmt(cx - 51 * s)},${fmt(cy - 4 * s)} ${fmt(cx - 42 * s)},${fmt(cy - 23 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(3 * s)}" stroke-linecap="round"/><path class="asset-crispr-grna-spacer" d="M${fmt(cx - 22 * s)},${fmt(cy - 6 * s)} h${fmt(32 * s)} M${fmt(cx - 13 * s)},${fmt(cy + 6 * s)} h${fmt(25 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.6 * s)}" stroke-linecap="round"/></g>`;
  const cut = `<g class="asset-crispr-cut-site"><path d="M${fmt(cx + 12 * s)},${fmt(cy + 9 * s)} l${fmt(10 * s)},${fmt(-13 * s)} M${fmt(cx + 19 * s)},${fmt(cy + 12 * s)} l${fmt(10 * s)},${fmt(-13 * s)}" stroke="#ffffff" stroke-width="${fmt(2.4 * s)}" stroke-linecap="round"/><circle class="asset-crispr-pam-dot" cx="${fmt(cx - 43 * s)}" cy="${fmt(cy - 23 * s)}" r="${fmt(5 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.7 * s)}"/></g>`;
  return `${baseLayer(cx, cy, s, palette)}<g class="asset-crispr-cas9" filter="url(#asset-soft-shadow)">${dnaBack}${dnaFront}${grna}${cas9}${cut}</g>`;
}

function guideRna(cx, cy, s, palette) {
  const backbone = `<path class="asset-grna-backbone" d="M${fmt(cx - 49 * s)},${fmt(cy + 17 * s)} C${fmt(cx - 37 * s)},${fmt(cy - 35 * s)} ${fmt(cx + 4 * s)},${fmt(cy - 47 * s)} ${fmt(cx + 28 * s)},${fmt(cy - 16 * s)} C${fmt(cx + 43 * s)},${fmt(cy + 4 * s)} ${fmt(cx + 26 * s)},${fmt(cy + 28 * s)} ${fmt(cx + 3 * s)},${fmt(cy + 13 * s)} C${fmt(cx - 11 * s)},${fmt(cy + 4 * s)} ${fmt(cx - 2 * s)},${fmt(cy - 13 * s)} ${fmt(cx + 15 * s)},${fmt(cy - 7 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(4.2 * s)}" stroke-linecap="round" stroke-linejoin="round"/>`;
  const accentBackbone = `<path class="asset-grna-scaffold-loop" d="M${fmt(cx - 45 * s)},${fmt(cy + 15 * s)} C${fmt(cx - 32 * s)},${fmt(cy - 28 * s)} ${fmt(cx - 2 * s)},${fmt(cy - 37 * s)} ${fmt(cx + 18 * s)},${fmt(cy - 16 * s)} C${fmt(cx + 32 * s)},${fmt(cy - 1 * s)} ${fmt(cx + 17 * s)},${fmt(cy + 15 * s)} ${fmt(cx + 3 * s)},${fmt(cy + 8 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.35 * s)}" stroke-linecap="round" stroke-linejoin="round"/>`;
  const cassette = `<g class="asset-grna-library-cassette"><rect x="${fmt(cx - 39 * s)}" y="${fmt(cy - 18 * s)}" width="${fmt(74 * s)}" height="${fmt(27 * s)}" rx="${fmt(10 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.25 * s)}" opacity="0.9"/><path d="M${fmt(cx - 32 * s)},${fmt(cy - 13 * s)} h${fmt(60 * s)}" stroke="#ffffff" stroke-width="${fmt(1.4 * s)}" opacity="0.78" stroke-linecap="round"/></g>`;
  const spacer = `<g class="asset-grna-spacer"><path d="M${fmt(cx - 33 * s)},${fmt(cy - 9 * s)} h${fmt(66 * s)}" stroke="${palette.accent}" stroke-width="${fmt(2.35 * s)}" stroke-linecap="round"/><path d="M${fmt(cx - 30 * s)},${fmt(cy + 4 * s)} h${fmt(50 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(1.7 * s)}" stroke-linecap="round" opacity="0.52"/></g>`;
  const bases = [-25, -15, -5, 5, 15, 25].map((x, index) => `<path class="asset-grna-base-tick" d="M${fmt(cx + x * s)},${fmt(cy - 9 * s)} v${fmt((index % 2 ? 14 : 11) * s)}" stroke="${index % 2 ? palette.stroke : palette.accent}" stroke-width="${fmt(1.15 * s)}" stroke-linecap="round" opacity="${index % 2 ? "0.48" : "0.72"}"/>`).join("");
  const target = `<g class="asset-grna-target-window"><rect x="${fmt(cx + 4 * s)}" y="${fmt(cy - 35 * s)}" width="${fmt(39 * s)}" height="${fmt(22 * s)}" rx="${fmt(9 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.55 * s)}"/><text x="${fmt(cx + 23.5 * s)}" y="${fmt(cy - 20 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(9.4 * s)}" font-weight="900" fill="${palette.accent}">sg</text></g>`;
  const pam = `<g class="asset-grna-pam-badge"><rect x="${fmt(cx + 22 * s)}" y="${fmt(cy + 10 * s)}" width="${fmt(26 * s)}" height="${fmt(14 * s)}" rx="${fmt(7 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.2 * s)}"/><text x="${fmt(cx + 35 * s)}" y="${fmt(cy + 20 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(6.3 * s)}" font-weight="900" fill="${palette.accent}">PAM</text></g>`;
  return `${baseLayer(cx, cy, s, palette)}<g filter="url(#asset-soft-shadow)">${backbone}${accentBackbone}${cassette}${spacer}${bases}${target}${pam}<circle class="asset-grna-five-prime" cx="${fmt(cx - 45 * s)}" cy="${fmt(cy + 17 * s)}" r="${fmt(5.2 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.55 * s)}"/><circle class="asset-grna-three-prime" cx="${fmt(cx + 43 * s)}" cy="${fmt(cy + 15 * s)}" r="${fmt(5.8 * s)}" fill="${palette.accent}" opacity="0.88"/></g>`;
}

function viralLibrary(cx, cy, s, palette) {
  const particle = `<g class="asset-lentiviral-particle">${virusParticle(cx - 26 * s, cy - 4 * s, 21 * s, palette)}<circle class="asset-lentiviral-capsid" cx="${fmt(cx - 26 * s)}" cy="${fmt(cy - 4 * s)}" r="${fmt(10 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.2 * s)}" opacity="0.92"/></g>`;
  const libraryStack = `<g class="asset-lentiviral-library-stack" filter="url(#asset-soft-shadow)"><rect x="${fmt(cx + 4 * s)}" y="${fmt(cy - 29 * s)}" width="${fmt(42 * s)}" height="${fmt(62 * s)}" rx="${fmt(10 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.35 * s)}" opacity="0.72"/><rect class="asset-lentiviral-vector-card" x="${fmt(cx + 12 * s)}" y="${fmt(cy - 36 * s)}" width="${fmt(42 * s)}" height="${fmt(66 * s)}" rx="${fmt(10 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2 * s)}"/><path class="asset-lentiviral-card-highlight asset-inner-highlight" d="M${fmt(cx + 19 * s)},${fmt(cy - 29 * s)} C${fmt(cx + 28 * s)},${fmt(cy - 34 * s)} ${fmt(cx + 42 * s)},${fmt(cy - 33 * s)} ${fmt(cx + 48 * s)},${fmt(cy - 24 * s)}" stroke="#ffffff" stroke-width="${fmt(1.5 * s)}" opacity="0.55" fill="none" stroke-linecap="round"/></g>`;
  const barcode = `<g class="asset-lentiviral-barcode"><path d="M${fmt(cx + 21 * s)},${fmt(cy - 19 * s)} h${fmt(23 * s)} M${fmt(cx + 21 * s)},${fmt(cy - 5 * s)} h${fmt(18 * s)} M${fmt(cx + 21 * s)},${fmt(cy + 9 * s)} h${fmt(23 * s)} M${fmt(cx + 21 * s)},${fmt(cy + 22 * s)} h${fmt(14 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.85 * s)}" stroke-linecap="round"/><circle cx="${fmt(cx + 46 * s)}" cy="${fmt(cy - 27 * s)}" r="${fmt(3.7 * s)}" fill="${palette.accent}" opacity="0.86"/></g>`;
  const payload = `<path class="asset-lentiviral-payload" d="M${fmt(cx - 7 * s)},${fmt(cy - 6 * s)} C${fmt(cx + 5 * s)},${fmt(cy - 22 * s)} ${fmt(cx + 22 * s)},${fmt(cy - 19 * s)} ${fmt(cx + 31 * s)},${fmt(cy - 7 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.15 * s)}" stroke-dasharray="${fmt(4 * s)} ${fmt(3 * s)}" stroke-linecap="round"/><path class="asset-lentiviral-guide-insert" d="M${fmt(cx - 15 * s)},${fmt(cy + 21 * s)} C${fmt(cx - 1 * s)},${fmt(cy + 33 * s)} ${fmt(cx + 16 * s)},${fmt(cy + 29 * s)} ${fmt(cx + 25 * s)},${fmt(cy + 17 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(1.45 * s)}" opacity="0.52" stroke-linecap="round"/>`;
  return `${baseLayer(cx, cy, s, palette)}${particle}${payload}${libraryStack}${barcode}<circle class="asset-lentiviral-multiplicity-dot" cx="${fmt(cx - 42 * s)}" cy="${fmt(cy - 30 * s)}" r="${fmt(3.2 * s)}" fill="${palette.accent}" opacity="0.72"/><circle class="asset-lentiviral-multiplicity-dot" cx="${fmt(cx - 4 * s)}" cy="${fmt(cy + 29 * s)}" r="${fmt(2.8 * s)}" fill="${palette.accent}" opacity="0.52"/>`;
}

function perturbSeq(cx, cy, s, palette) {
  const droplet = dropletAsset(cx - 18 * s, cy + 2 * s, s * 0.78, palette);
  const cas9 = `<g transform="translate(${fmt(27 * s)} ${fmt(-3 * s)})">${crisprMini(cx, cy, s, palette)}</g>`;
  const readout = `<rect x="${fmt(cx + 22 * s)}" y="${fmt(cy + 16 * s)}" width="${fmt(42 * s)}" height="${fmt(24 * s)}" rx="${fmt(7 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.7 * s)}"/><path d="M${fmt(cx + 29 * s)},${fmt(cy + 24 * s)} h${fmt(28 * s)} M${fmt(cx + 29 * s)},${fmt(cy + 32 * s)} h${fmt(20 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.5 * s)}" stroke-linecap="round"/><path d="M${fmt(cx + 7 * s)},${fmt(cy + 28 * s)} C${fmt(cx + 16 * s)},${fmt(cy + 38 * s)} ${fmt(cx + 22 * s)},${fmt(cy + 34 * s)} ${fmt(cx + 29 * s)},${fmt(cy + 28 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.1 * s)}" stroke-linecap="round"/><circle cx="${fmt(cx + 65 * s)}" cy="${fmt(cy + 41 * s)}" r="${fmt(5 * s)}" fill="${palette.accent}"/>`;
  return `${droplet}${cas9}${readout}`;
}

function pooledScreen(cx, cy, s, palette) {
  const wells = [];
  for (let row = 0; row < 4; row += 1) {
    for (let col = 0; col < 5; col += 1) {
      const hit = (row + col) % 3 === 0;
      wells.push(`<circle class="asset-pooled-screen-well ${hit ? "asset-pooled-screen-hit-well" : ""}" cx="${fmt(cx - 29 * s + col * 14 * s)}" cy="${fmt(cy - 19 * s + row * 13 * s)}" r="${fmt(4.2 * s)}" fill="${hit ? palette.accent : palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(0.9 * s)}" opacity="${hit ? 0.92 : 0.68}"/>`);
    }
  }
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-pooled-screen" filter="url(#asset-soft-shadow)"><rect class="asset-pooled-screen-grid" x="${fmt(cx - 45 * s)}" y="${fmt(cy - 34 * s)}" width="${fmt(90 * s)}" height="${fmt(68 * s)}" rx="${fmt(12 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.1 * s)}"/>${wells.join("")}<path class="asset-pooled-screen-decision-tail" d="M${fmt(cx + 25 * s)},${fmt(cy + 26 * s)} l${fmt(16 * s)},${fmt(15 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(3 * s)}" stroke-linecap="round"/><circle class="asset-pooled-screen-pool-lens" cx="${fmt(cx + 18 * s)}" cy="${fmt(cy + 19 * s)}" r="${fmt(13 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.3 * s)}"/><path class="asset-screening-readout" d="M${fmt(cx - 36 * s)},${fmt(cy - 28 * s)} h${fmt(27 * s)} M${fmt(cx - 36 * s)},${fmt(cy + 29 * s)} h${fmt(19 * s)}" stroke="#ffffff" stroke-width="${fmt(1.35 * s)}" stroke-linecap="round" opacity="0.48"/></g>`;
}

function arrayedScreen(cx, cy, s, palette) {
  const wells = [];
  for (let row = 0; row < 3; row += 1) {
    for (let col = 0; col < 4; col += 1) {
      const hit = row === 1 && col === 2;
      wells.push(`<rect class="asset-arrayed-screen-well ${hit ? "asset-arrayed-screen-hit-well" : ""}" x="${fmt(cx - 34 * s + col * 18 * s)}" y="${fmt(cy - 24 * s + row * 17 * s)}" width="${fmt(12 * s)}" height="${fmt(12 * s)}" rx="${fmt(3 * s)}" fill="${hit ? palette.accent : palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1 * s)}" opacity="${hit ? 0.96 : 0.62}"/>`);
    }
  }
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-arrayed-screen" filter="url(#asset-soft-shadow)"><rect class="asset-arrayed-screen-grid" x="${fmt(cx - 46 * s)}" y="${fmt(cy - 35 * s)}" width="${fmt(92 * s)}" height="${fmt(70 * s)}" rx="${fmt(12 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.1 * s)}"/>${wells.join("")}<path class="asset-arrayed-screen-check asset-screening-hit-call" d="M${fmt(cx + 20 * s)},${fmt(cy + 23 * s)} l${fmt(12 * s)},${fmt(12 * s)} l${fmt(18 * s)},${fmt(-25 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.8 * s)}" stroke-linecap="round" stroke-linejoin="round"/><path class="asset-arrayed-screen-row-labels" d="M${fmt(cx - 39 * s)},${fmt(cy - 30 * s)} h${fmt(20 * s)} M${fmt(cx - 39 * s)},${fmt(cy + 31 * s)} h${fmt(14 * s)}" stroke="#ffffff" stroke-width="${fmt(1.35 * s)}" stroke-linecap="round" opacity="0.46"/></g>`;
}

function geneEditState(cx, cy, s, palette, label, mode) {
  const stateClass = mode === "up" ? "activation" : mode === "down" ? "knockdown" : mode === "block" ? "inhibition" : "base-editor";
  const arrow = mode === "up"
    ? `<path class="asset-gene-edit-direction-arrow asset-gene-edit-activation-arrow" d="M${fmt(cx + 30 * s)},${fmt(cy + 17 * s)} V${fmt(cy - 19 * s)} M${fmt(cx + 18 * s)},${fmt(cy - 8 * s)} L${fmt(cx + 30 * s)},${fmt(cy - 20 * s)} L${fmt(cx + 42 * s)},${fmt(cy - 8 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(3 * s)}" stroke-linecap="round" stroke-linejoin="round"/>`
    : mode === "down"
      ? `<path class="asset-gene-edit-direction-arrow asset-gene-edit-knockdown-arrow" d="M${fmt(cx + 30 * s)},${fmt(cy - 21 * s)} V${fmt(cy + 17 * s)} M${fmt(cx + 18 * s)},${fmt(cy + 6 * s)} L${fmt(cx + 30 * s)},${fmt(cy + 18 * s)} L${fmt(cx + 42 * s)},${fmt(cy + 6 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(3 * s)}" stroke-linecap="round" stroke-linejoin="round"/>`
      : mode === "block"
        ? `<path class="asset-gene-edit-direction-arrow asset-gene-edit-inhibition-block" d="M${fmt(cx + 16 * s)},${fmt(cy - 18 * s)} L${fmt(cx + 45 * s)},${fmt(cy + 11 * s)} M${fmt(cx + 45 * s)},${fmt(cy - 18 * s)} L${fmt(cx + 16 * s)},${fmt(cy + 11 * s)}" stroke="${palette.accent}" stroke-width="${fmt(3.2 * s)}" stroke-linecap="round"/>`
        : `<path class="asset-gene-edit-direction-arrow asset-base-editor-edit-mark" d="M${fmt(cx + 14 * s)},${fmt(cy - 16 * s)} h${fmt(33 * s)} M${fmt(cx + 30 * s)},${fmt(cy - 31 * s)} v${fmt(31 * s)}" stroke="${palette.accent}" stroke-width="${fmt(3 * s)}" stroke-linecap="round"/>`;
  return `${baseLayer(cx, cy, s, palette, "panel")}<g class="asset-gene-edit-state asset-gene-edit-${stateClass}" filter="url(#asset-soft-shadow)"><rect class="asset-gene-edit-frame" x="${fmt(cx - 48 * s)}" y="${fmt(cy - 30 * s)}" width="${fmt(96 * s)}" height="${fmt(60 * s)}" rx="${fmt(13 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.1 * s)}"/><path class="asset-gene-edit-locus-axis" d="M${fmt(cx - 37 * s)},${fmt(cy)} H${fmt(cx + 2 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(2.5 * s)}" stroke-linecap="round"/><rect class="asset-gene-edit-target-exon" x="${fmt(cx - 31 * s)}" y="${fmt(cy - 10 * s)}" width="${fmt(17 * s)}" height="${fmt(20 * s)}" rx="${fmt(4 * s)}" fill="${palette.accent}" opacity="0.9"/><rect class="asset-gene-edit-editor-block" x="${fmt(cx - 8 * s)}" y="${fmt(cy - 13 * s)}" width="${fmt(24 * s)}" height="${fmt(26 * s)}" rx="${fmt(5 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.6 * s)}"/>${arrow}<text class="asset-gene-edit-label" x="${fmt(cx)}" y="${fmt(cy + 42 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(12 * s)}" font-weight="900" fill="${palette.accent}">${label}</text></g>`;
}

