  const nick = `<path class="asset-prime-editor-nick-site" d="M${fmt(cx + 12 * s)},${fmt(cy + 4 * s)} l${fmt(11 * s)},${fmt(-13 * s)} M${fmt(cx + 18 * s)},${fmt(cy + 8 * s)} l${fmt(11 * s)},${fmt(-13 * s)}" stroke="${palette.accent}" stroke-width="${fmt(2.4 * s)}" stroke-linecap="round"/><g class="asset-prime-editor-rt-badge"><circle cx="${fmt(cx + 41 * s)}" cy="${fmt(cy + 22 * s)}" r="${fmt(8 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.7 * s)}"/><text class="asset-prime-editor-rt-label" x="${fmt(cx + 41 * s)}" y="${fmt(cy + 25 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(7 * s)}" font-weight="900" fill="${palette.accent}">RT</text></g>`;
