  const anchorScaffold = `<g class="asset-lead-series-anchor-scaffold"><circle cx="${fmt(cx)}" cy="${fmt(cy - 36 * s)}" r="${fmt(9 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.4 * s)}"/><path d="M${fmt(cx - 4 * s)},${fmt(cy - 36 * s)} h${fmt(8 * s)} M${fmt(cx)},${fmt(cy - 40 * s)} v${fmt(8 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.5 * s)}" stroke-linecap="round"/></g>`;
