function selectivityPanelAsset(cx, cy, s, palette) {
  const field = `<path class="asset-selectivity-landscape" d="M${fmt(cx - 50 * s)},${fmt(cy - 23 * s)} C${fmt(cx - 29 * s)},${fmt(cy - 48 * s)} ${fmt(cx + 22 * s)},${fmt(cy - 45 * s)} ${fmt(cx + 47 * s)},${fmt(cy - 17 * s)} C${fmt(cx + 37 * s)},${fmt(cy + 24 * s)} ${fmt(cx - 3 * s)},${fmt(cy + 45 * s)} ${fmt(cx - 41 * s)},${fmt(cy + 22 * s)} C${fmt(cx - 55 * s)},${fmt(cy + 10 * s)} ${fmt(cx - 63 * s)},${fmt(cy - 3 * s)} ${fmt(cx - 50 * s)},${fmt(cy - 23 * s)} Z" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.1 * s)}"/>`;
  const cells = [
    [-33, -16, 5.8, "background"], [-12, -24, 5.2, "background"], [7, -15, 8.1, "target"], [29, -22, 5.1, "background"],
    [-41, 4, 4.8, "background"], [-18, 5, 5.4, "offtarget"], [7, 7, 5, "background"], [28, 8, 5.7, "offtarget"],
    [-26, 24, 4.5, "background"], [-2, 26, 5.2, "background"], [23, 26, 4.8, "background"]
  ].map(([x, y, r, kind], index) => {
    const fill = kind === "target" ? palette.accent : kind === "offtarget" ? palette.secondary : "#ffffff";
    const opacity = kind === "target" ? 0.94 : kind === "offtarget" ? 0.72 : 0.6;
    const klass = kind === "target" ? " asset-selectivity-target-cell" : kind === "offtarget" ? " asset-selectivity-offtarget-cell" : "";
    return `<circle class="asset-selectivity-landscape-cell${klass}" data-selectivity-cell="${index + 1}" cx="${fmt(cx + Number(x) * s)}" cy="${fmt(cy + Number(y) * s)}" r="${fmt(Number(r) * s)}" fill="${fill}" stroke="${palette.accent}" stroke-width="${fmt(0.95 * s)}" opacity="${opacity}"/>`;
  }).join("");
  const targetBadge = `<g class="asset-selectivity-target-badge"><circle cx="${fmt(cx + 41 * s)}" cy="${fmt(cy - 30 * s)}" r="${fmt(13 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.4 * s)}"/><path d="M${fmt(cx + 34 * s)},${fmt(cy - 30 * s)} l${fmt(5 * s)},${fmt(5 * s)} l${fmt(10 * s)},${fmt(-13 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2 * s)}" stroke-linecap="round" stroke-linejoin="round"/></g>`;
  const ratio = `<g class="asset-selectivity-ratio"><path d="M${fmt(cx - 44 * s)},${fmt(cy + 33 * s)} C${fmt(cx - 30 * s)},${fmt(cy + 42 * s)} ${fmt(cx - 10 * s)},${fmt(cy + 42 * s)} ${fmt(cx + 4 * s)},${fmt(cy + 31 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.1 * s)}" stroke-linecap="round"/><circle cx="${fmt(cx - 44 * s)}" cy="${fmt(cy + 33 * s)}" r="${fmt(4.2 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1 * s)}"/><circle cx="${fmt(cx + 4 * s)}" cy="${fmt(cy + 31 * s)}" r="${fmt(5.2 * s)}" fill="${palette.accent}" stroke="#ffffff" stroke-width="${fmt(1 * s)}"/></g>`;
  const targetBeam = `<path class="asset-selectivity-target-beam" d="M${fmt(cx + 7 * s)},${fmt(cy - 39 * s)} V${fmt(cy + 22 * s)} M${fmt(cx - 46 * s)},${fmt(cy - 15 * s)} H${fmt(cx + 44 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.15 * s)}" stroke-dasharray="${fmt(3 * s)} ${fmt(3 * s)}" opacity="0.47"/>`;
  const offTargetWarning = `<g class="asset-selectivity-offtarget-warning"><path d="M${fmt(cx + 32 * s)},${fmt(cy + 18 * s)} l${fmt(10 * s)},${fmt(17 * s)} h${fmt(-20 * s)} Z" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}"/><circle cx="${fmt(cx + 32 * s)}" cy="${fmt(cy + 30 * s)}" r="${fmt(1.3 * s)}" fill="${palette.accent}"/></g>`;
  return `${baseLayer(cx, cy, s, palette)}<g filter="url(#asset-soft-shadow)">${field}<path d="M${fmt(cx - 40 * s)},${fmt(cy - 30 * s)} C${fmt(cx - 17 * s)},${fmt(cy - 39 * s)} ${fmt(cx + 19 * s)},${fmt(cy - 36 * s)} ${fmt(cx + 39 * s)},${fmt(cy - 18 * s)}" stroke="#ffffff" stroke-width="${fmt(1.5 * s)}" opacity="0.42" fill="none" stroke-linecap="round"/>${targetBeam}${cells}${targetBadge}${ratio}${offTargetWarning}</g>`;
}

