  const halfLifeBand = `<path class="asset-pk-profile-half-life-band" d="M${fmt(cx - 13 * s)},${fmt(cy - 25 * s)} V${fmt(cy + 22 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.15 * s)}" stroke-dasharray="${fmt(3 * s)} ${fmt(3 * s)}" opacity="0.5"/><rect class="asset-pk-profile-half-life-band" x="${fmt(cx - 27 * s)}" y="${fmt(cy - 39 * s)}" width="${fmt(34 * s)}" height="${fmt(12 * s)}" rx="${fmt(6 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(0.9 * s)}" opacity="0.94"/>`;
