  const objective = (x, y, rotate, length, className) => `<g class="asset-microscope-objective ${className}" transform="rotate(${rotate} ${fmt(cx + x * s)} ${fmt(cy + y * s)})"><path d="M${fmt(cx + (x - 3.3) * s)},${fmt(cy + y * s)} h${fmt(6.6 * s)} l${fmt(1.8 * s)},${fmt(length * s)} h${fmt(-10.2 * s)} Z" fill="${t.panel}" stroke="${t.accent}" stroke-width="${fmt(0.95 * s)}"/><path d="M${fmt(cx + (x - 3) * s)},${fmt(cy + (y + length - 3) * s)} h${fmt(6 * s)}" stroke="${t.stroke}" stroke-width="${fmt(0.85 * s)}" stroke-linecap="round"/></g>`;
