function instrumentTones(palette) {
  if (palette.styleProfile === "publication-line") {
    return {
      halo: "#ffffff",
      body: "#ffffff",
      body2: "#ffffff",
      panel: "#ffffff",
      inset: "#ffffff",
      dark: "#111827",
      glass: "#ffffff",
      accent: "#111827",
      led: "#111827",
      metal: "#ffffff",
      stroke: "#111827",
      text: "#111827"
    };
  }
  if (palette.styleProfile === "dark-talk") {
    return {
      halo: "#172033",
      body: "#263241",
      body2: "#3a4657",
      panel: "#111827",
      inset: "#0b1120",
      dark: "#020617",
      glass: "#13283d",
      accent: "#38bdf8",
      led: "#67e8f9",
      metal: "#64748b",
      stroke: "#e2e8f0",
      text: "#f8fafc"
    };
  }
  if (palette.styleProfile === "risk-warning") {
    return {
      halo: "#fff7ed",
      body: "#f8fafc",
      body2: "#e2e8f0",
      panel: "#ffffff",
      inset: "#1f2937",
      dark: "#111827",
      glass: "#fee2e2",
      accent: "#dc2626",
      led: "#f97316",
      metal: "#cbd5e1",
      stroke: "#7f1d1d",
      text: "#111827"
    };
  }
  return {
    halo: "#eef6fb",
    body: "#f8fafc",
    body2: "#d8dee8",
    panel: "#ffffff",
    inset: "#202936",
    dark: "#111827",
    glass: "#dbeafe",
    accent: palette.accent,
    led: "#38bdf8",
    metal: "#cbd5e1",
    stroke: "#415166",
    text: "#0f172a"
  };
}

function instrumentBaseLayer(cx, cy, s, palette, shape = "panel") {
  const tones = instrumentTones(palette);
  return baseLayer(cx, cy, s, { ...palette, fill: tones.body, secondary: tones.halo, stroke: tones.stroke, accent: tones.accent }, shape);
}

function instrumentCompactBaseLayer(cx, cy, s, palette) {
  const tones = instrumentTones(palette);
  const warningGlow = palette.accent === "#dc2626"
    ? `<ellipse class="asset-warning-glow" cx="${fmt(cx)}" cy="${fmt(cy)}" rx="${fmt(56 * s)}" ry="${fmt(39 * s)}" fill="${palette.accent}" opacity="${fmt(palette.glowOpacity)}" filter="url(#asset-warning-glow)"/>`
    : "";
  return [
    warningGlow,
    `<ellipse class="asset-contact-shadow" cx="${fmt(cx)}" cy="${fmt(cy + 35 * s)}" rx="${fmt(45 * s)}" ry="${fmt(7.5 * s)}" fill="#0f172a" opacity="${fmt(palette.contactOpacity)}" filter="url(#asset-contact-shadow)"/>`,
    `<rect class="asset-soft-body-gradient" x="${fmt(cx - 53 * s)}" y="${fmt(cy - 37 * s)}" width="${fmt(106 * s)}" height="${fmt(76 * s)}" rx="${fmt(17 * s)}" fill="${tones.halo}" opacity="${fmt(palette.surfaceOpacity)}"/>`,
    `<rect class="asset-body-depth-overlay" x="${fmt(cx - 49 * s)}" y="${fmt(cy - 35 * s)}" width="${fmt(98 * s)}" height="${fmt(72 * s)}" rx="${fmt(16 * s)}" fill="url(#asset-body-depth)" opacity="${fmt(palette.depthOpacity)}"/>`
  ].join("");
}

function instrumentGloss(cx, cy, s, tones, width = 80, y = -32, curve = 10) {
  return `<path class="asset-instrument-material-highlight" d="M${fmt(cx - width * 0.5 * s)},${fmt(cy + y * s)} C${fmt(cx - width * 0.24 * s)},${fmt(cy + (y - curve) * s)} ${fmt(cx + width * 0.22 * s)},${fmt(cy + (y - curve) * s)} ${fmt(cx + width * 0.5 * s)},${fmt(cy + y * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.6 * s)}" opacity="${tones.body === "#ffffff" ? "0.18" : "0.62"}" stroke-linecap="round"/>`;
}

function instrumentSideRim(cx, cy, s, tones, x = 42, y1 = -24, y2 = 34) {
  return `<path class="asset-instrument-side-rim" d="M${fmt(cx + x * s)},${fmt(cy + y1 * s)} v${fmt((y2 - y1) * s)}" stroke="${tones.metal}" stroke-width="${fmt(1.6 * s)}" opacity="0.78" stroke-linecap="round"/>`;
}

function instrumentFeet(cx, cy, s, tones, left = -34, right = 34, y = 49) {
  return `<path class="asset-instrument-foot" d="M${fmt(cx + left * s)},${fmt(cy + y * s)} v${fmt(6 * s)} M${fmt(cx + right * s)},${fmt(cy + y * s)} v${fmt(6 * s)}" stroke="${tones.dark}" stroke-width="${fmt(1.25 * s)}" stroke-linecap="round" opacity="0.5"/>`;
}

function instrumentMicroScrews(points, cx, cy, s, tones, className = "asset-instrument-fastener") {
  return points.map(([x, y]) => `<circle class="${className}" cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" r="${fmt(1.65 * s)}" fill="${tones.dark}" opacity="${tones.body === "#ffffff" ? "0.2" : "0.58"}"/>`).join("");
}

function sequencerAssetV3(cx, cy, s, palette) {
  const t = instrumentTones(palette);
  const isLine = palette.styleProfile === "publication-line";
  const groupFilter = "";
  const brightOpacity = isLine ? "0.16" : "0.66";
  const glassOpacity = isLine ? "0.06" : "0.72";
  const bayFill = isLine ? t.panel : "#eaf2ff";
  const body = `<g class="asset-sequencer-body"><path d="M${fmt(cx - 56 * s)},${fmt(cy - 36 * s)} h${fmt(86 * s)} l${fmt(24 * s)},${fmt(12 * s)} v${fmt(61 * s)} q0,${fmt(10 * s)} ${fmt(-10 * s)},${fmt(10 * s)} h${fmt(-100 * s)} q${fmt(-10 * s)},0 ${fmt(-10 * s)},${fmt(-10 * s)} v${fmt(-62 * s)} q0,${fmt(-11 * s)} ${fmt(10 * s)},${fmt(-11 * s)} Z" fill="${t.body}" stroke="${t.stroke}" stroke-width="${fmt(2.15 * s)}"/><path class="asset-sequencer-top-lid" d="M${fmt(cx - 49 * s)},${fmt(cy - 37 * s)} h${fmt(74 * s)} l${fmt(20 * s)},${fmt(10 * s)} h${fmt(-86 * s)} q${fmt(-11 * s)},0 ${fmt(-8 * s)},${fmt(-10 * s)} Z" fill="${t.body2}" stroke="${t.metal}" stroke-width="${fmt(1.1 * s)}"/><path class="asset-sequencer-side-panel" d="M${fmt(cx + 30 * s)},${fmt(cy - 36 * s)} l${fmt(24 * s)},${fmt(12 * s)} v${fmt(60 * s)} q0,${fmt(9 * s)} ${fmt(-9 * s)},${fmt(9 * s)} h${fmt(-18 * s)} q${fmt(7 * s)},${fmt(-7 * s)} ${fmt(7 * s)},${fmt(-16 * s)} v${fmt(-47 * s)} q0,${fmt(-12 * s)} ${fmt(-4 * s)},${fmt(-18 * s)} Z" fill="${t.body2}" stroke="${t.metal}" stroke-width="${fmt(1.2 * s)}"/><path d="M${fmt(cx - 45 * s)},${fmt(cy - 34 * s)} C${fmt(cx - 16 * s)},${fmt(cy - 44 * s)} ${fmt(cx + 13 * s)},${fmt(cy - 42 * s)} ${fmt(cx + 34 * s)},${fmt(cy - 30 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.8 * s)}" opacity="${brightOpacity}" stroke-linecap="round"/></g>`;
  const runLanes = [-30, -22, -14, -6, 2, 10, 18, 26].map((x, index) => `<path class="asset-sequencer-run-lane" d="M${fmt(cx + x * s)},${fmt(cy - 19 * s)} v${fmt(14 * s)}" stroke="${index % 3 === 0 ? t.accent : t.stroke}" stroke-width="${fmt(1.05 * s)}" stroke-linecap="round" opacity="${index % 3 === 0 ? 0.76 : 0.36}"/>`).join("");
  const screenTraces = [-23, -11, 1, 13].map((x, index) => `<path class="asset-sequencer-readout-stack" d="M${fmt(cx + x * s)},${fmt(cy - 27 * s)} h${fmt(18 * s)}" stroke="${index % 2 ? t.stroke : t.accent}" stroke-width="${fmt(0.9 * s)}" stroke-linecap="round" opacity="${index % 2 ? 0.32 : 0.58}"/>`).join("");
  const screen = `<g class="asset-sequencer-screen"><rect x="${fmt(cx - 43 * s)}" y="${fmt(cy - 31 * s)}" width="${fmt(76 * s)}" height="${fmt(29 * s)}" rx="${fmt(5 * s)}" fill="${t.panel}" stroke="${t.metal}" stroke-width="${fmt(1.2 * s)}"/><rect class="asset-sequencer-readout-stack" x="${fmt(cx - 36 * s)}" y="${fmt(cy - 27 * s)}" width="${fmt(38 * s)}" height="${fmt(18 * s)}" rx="${fmt(3 * s)}" fill="${t.glass}" opacity="${glassOpacity}" stroke="${t.accent}" stroke-width="${fmt(0.8 * s)}"/><circle class="asset-sequencer-touch-start" cx="${fmt(cx + 21 * s)}" cy="${fmt(cy - 17 * s)}" r="${fmt(7.4 * s)}" fill="${t.glass}" stroke="${t.accent}" stroke-width="${fmt(1 * s)}" opacity="0.82"/><path d="M${fmt(cx + 17.5 * s)},${fmt(cy - 17 * s)} h${fmt(7 * s)} M${fmt(cx + 21 * s)},${fmt(cy - 20.5 * s)} v${fmt(7 * s)}" stroke="${t.accent}" stroke-width="${fmt(0.9 * s)}" stroke-linecap="round" opacity="0.72"/>${screenTraces}${runLanes}</g>`;
  const flowCell = `<g class="asset-sequencer-flowcell-bay"><path d="M${fmt(cx - 43 * s)},${fmt(cy + 1 * s)} h${fmt(70 * s)} q${fmt(5 * s)},0 ${fmt(5 * s)},${fmt(5 * s)} v${fmt(20 * s)} q0,${fmt(5 * s)} ${fmt(-5 * s)},${fmt(5 * s)} h${fmt(-70 * s)} q${fmt(-5 * s)},0 ${fmt(-5 * s)},${fmt(-5 * s)} v${fmt(-20 * s)} q0,${fmt(-5 * s)} ${fmt(5 * s)},${fmt(-5 * s)} Z" fill="${bayFill}" stroke="${t.metal}" stroke-width="${fmt(1.15 * s)}"/><rect class="asset-sequencer-cartridge" x="${fmt(cx - 35 * s)}" y="${fmt(cy + 8 * s)}" width="${fmt(47 * s)}" height="${fmt(13 * s)}" rx="${fmt(3 * s)}" fill="${t.panel}" stroke="${t.accent}" stroke-width="${fmt(1.05 * s)}"/><path class="asset-sequencer-optics-window" d="M${fmt(cx - 31 * s)},${fmt(cy + 15 * s)} h${fmt(36 * s)}" stroke="${t.accent}" stroke-width="${fmt(1.35 * s)}" stroke-linecap="round"/><path class="asset-sequencer-optics-window" d="M${fmt(cx + 18 * s)},${fmt(cy + 8 * s)} h${fmt(8 * s)} v${fmt(13 * s)} h${fmt(-8 * s)} Z" fill="${t.glass}" stroke="${t.accent}" stroke-width="${fmt(0.8 * s)}" opacity="0.86"/></g>`;
  const ledBand = `<g class="asset-sequencer-led-band"><rect x="${fmt(cx - 55 * s)}" y="${fmt(cy + 24 * s)}" width="${fmt(109 * s)}" height="${fmt(12 * s)}" rx="${fmt(3 * s)}" fill="${t.led}" opacity="${isLine ? "0.06" : "0.25"}"/><path d="M${fmt(cx - 51 * s)},${fmt(cy + 25.4 * s)} h${fmt(91 * s)}" stroke="#ffffff" stroke-width="${fmt(1.1 * s)}" opacity="${brightOpacity}"/><circle class="asset-sequencer-status-light" cx="${fmt(cx + 45 * s)}" cy="${fmt(cy + 30 * s)}" r="${fmt(3.5 * s)}" fill="${t.led}" stroke="${t.stroke}" stroke-width="${fmt(0.7 * s)}"/></g>`;
  const drawerSlots = [-30, -18, -6, 6].map((x, index) => `<rect class="asset-sequencer-sample-tray" x="${fmt(cx + x * s)}" y="${fmt(cy + 39 * s)}" width="${fmt(8 * s)}" height="${fmt(5.4 * s)}" rx="${fmt(1.5 * s)}" fill="${index % 2 ? t.panel : t.glass}" stroke="${t.metal}" stroke-width="${fmt(0.65 * s)}" opacity="0.9"/>`).join("");
  const door = `<g class="asset-sequencer-door"><rect class="asset-sequencer-reagent-drawer" x="${fmt(cx - 40 * s)}" y="${fmt(cy + 35 * s)}" width="${fmt(75 * s)}" height="${fmt(12 * s)}" rx="${fmt(3.5 * s)}" fill="${t.panel}" stroke="${t.metal}" stroke-width="${fmt(1.05 * s)}"/><path class="asset-sequencer-cartridge" d="M${fmt(cx - 33 * s)},${fmt(cy + 36.6 * s)} h${fmt(60 * s)}" stroke="${t.accent}" stroke-width="${fmt(1.15 * s)}" stroke-linecap="round" opacity="0.66"/>${drawerSlots}</g>`;
  const vents = Array.from({ length: 10 }, (_, i) => `<path class="asset-sequencer-vent asset-sequencer-vent-array" d="M${fmt(cx + 38 * s)},${fmt(cy - 10 * s + i * 5.6 * s)} h${fmt(8 * s)}" stroke="${t.dark}" stroke-width="${fmt(1.05 * s)}" stroke-linecap="round" opacity="0.42"/>`).join("");
  const polish = `${instrumentGloss(cx - 4 * s, cy, s, t, 84, -35, 9)}${instrumentSideRim(cx, cy, s, t, 43, -21, 37)}${instrumentFeet(cx, cy, s, t, -41, 38, 45)}${instrumentMicroScrews([[-48, -27], [31, -22], [-48, 40], [43, 40]], cx, cy, s, t)}`;
  return `${instrumentCompactBaseLayer(cx, cy, s, palette)}<g${groupFilter}>${body}${polish}${screen}${flowCell}${ledBand}${door}${vents}</g>`;
}

