  const liquid = `<path class="asset-pipette-droplet" d="M${fmt(cx + 25 * s)},${fmt(cy + 28 * s)} C${fmt(cx + 36 * s)},${fmt(cy + 39 * s)} ${fmt(cx + 17 * s)},${fmt(cy + 47 * s)} ${fmt(cx + 16 * s)},${fmt(cy + 33 * s)} C${fmt(cx + 18 * s)},${fmt(cy + 30 * s)} ${fmt(cx + 21 * s)},${fmt(cy + 28 * s)} ${fmt(cx + 25 * s)},${fmt(cy + 28 * s)} Z" fill="${palette.accent}" opacity="0.78"/><circle cx="${fmt(cx + 30 * s)}" cy="${fmt(cy + 48 * s)}" r="${fmt(2.6 * s)}" fill="${palette.accent}" opacity="0.45"/>`;
