  const rotor = `<g class="asset-centrifuge-rotor"><ellipse class="asset-centrifuge-rotor-bowl" cx="${fmt(cx)}" cy="${fmt(cy - 2 * s)}" rx="${fmt(29 * s)}" ry="${fmt(25 * s)}" fill="${t.glass}" stroke="${t.accent}" stroke-width="${fmt(1.55 * s)}" opacity="${isLine ? "0.28" : "0.86"}"/><circle class="asset-centrifuge-rotor-hub" cx="${fmt(cx)}" cy="${fmt(cy - 2 * s)}" r="${fmt(7 * s)}" fill="${t.panel}" stroke="${t.accent}" stroke-width="${fmt(1.05 * s)}"/><path class="asset-centrifuge-rotor-arm" d="M${fmt(cx)},${fmt(cy - 2 * s)} l${fmt(22 * s)},${fmt(-10 * s)} M${fmt(cx)},${fmt(cy - 2 * s)} l${fmt(-22 * s)},${fmt(-10 * s)} M${fmt(cx)},${fmt(cy - 2 * s)} v${fmt(23 * s)}" stroke="${t.accent}" stroke-width="${fmt(2.45 * s)}" stroke-linecap="round"/>${bucket(23, -13, 58, true)}${bucket(-23, -13, -58, true)}${bucket(0, 21, 0, false)}<path class="asset-centrifuge-spin-arrow" d="M${fmt(cx - 26 * s)},${fmt(cy + 5 * s)} C${fmt(cx - 17 * s)},${fmt(cy + 20 * s)} ${fmt(cx + 14 * s)},${fmt(cy + 22 * s)} ${fmt(cx + 25 * s)},${fmt(cy + 5 * s)}" fill="none" stroke="${t.accent}" stroke-width="${fmt(1.25 * s)}" stroke-linecap="round" opacity="0.58"/><path d="M${fmt(cx + 22 * s)},${fmt(cy + 4 * s)} l${fmt(4 * s)},${fmt(1 * s)} l${fmt(-2 * s)},${fmt(4 * s)}" fill="none" stroke="${t.accent}" stroke-width="${fmt(1 * s)}" stroke-linecap="round" stroke-linejoin="round" opacity="0.58"/></g>`;
  const controls = `<g class="asset-centrifuge-control-panel"><rect class="asset-centrifuge-display" x="${fmt(cx + 22 * s)}" y="${fmt(cy + 20 * s)}" width="${fmt(22 * s)}" height="${fmt(12 * s)}" rx="${fmt(5 * s)}" fill="${t.panel}" stroke="${t.accent}" stroke-width="${fmt(0.95 * s)}"/><path d="M${fmt(cx + 27 * s)},${fmt(cy + 26 * s)} h${fmt(8 * s)}" stroke="${t.accent}" stroke-width="${fmt(0.85 * s)}" stroke-linecap="round"/><circle class="asset-centrifuge-status-light" cx="${fmt(cx + 40 * s)}" cy="${fmt(cy + 26 * s)}" r="${fmt(2.4 * s)}" fill="${t.led}" stroke="${t.stroke}" stroke-width="${fmt(0.55 * s)}"/><path class="asset-centrifuge-lid-lock" d="M${fmt(cx - 42 * s)},${fmt(cy + 20 * s)} h${fmt(16 * s)}" stroke="${t.stroke}" stroke-width="${fmt(1.35 * s)}" stroke-linecap="round" opacity="0.46"/></g>`;
