  return `${baseLayer(cx, cy, s, palette, "panel")}<g filter="url(#asset-soft-shadow)">${tile}${masks}${overlay}${legend}${badge}<path class="asset-segmentation-glass-highlight" d="M${fmt(cx - 42 * s)},${fmt(cy - 31 * s)} h${fmt(31 * s)}" stroke="#ffffff" stroke-width="${fmt(1.7 * s)}" opacity="0.55" stroke-linecap="round"/></g>`;
