  const axes = `<path d="M${fmt(cx - 36 * s)},${fmt(cy + 31 * s)} C${fmt(cx - 10 * s)},${fmt(cy + 8 * s)} ${fmt(cx + 17 * s)},${fmt(cy - 9 * s)} ${fmt(cx + 39 * s)},${fmt(cy - 31 * s)} M${fmt(cx - 32 * s)},${fmt(cy - 27 * s)} C${fmt(cx - 4 * s)},${fmt(cy - 4 * s)} ${fmt(cx + 19 * s)},${fmt(cy + 14 * s)} ${fmt(cx + 40 * s)},${fmt(cy + 33 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.8 * s)}" stroke-dasharray="${fmt(5 * s)} ${fmt(4 * s)}" opacity="0.68"/>`;
