function neighborhoodGraph(cx, cy, s, palette) {
  const nodes = [
    [-32, -17, 0.24],
    [-9, -4, 0.3],
    [17, -21, 0.23],
    [34, 9, 0.27],
    [-21, 24, 0.26],
    [9, 27, 0.25],
    [3, 5, 0.21]
  ];
  const edges = [[0, 1, 0.52], [1, 2, 0.62], [1, 4, 0.72], [1, 6, 0.82], [6, 3, 0.62], [6, 5, 0.76], [4, 5, 0.58], [3, 5, 0.7], [2, 3, 0.46]].map(([a, b, weight]) => {
    const [x1, y1] = nodes[a];
    const [x2, y2] = nodes[b];
    const mx = (x1 + x2) / 2 + (a % 2 ? 4 : -4);
    const my = (y1 + y2) / 2 + (b % 2 ? -3 : 3);
    return `<path class="asset-neighborhood-edge ${weight > 0.7 ? "asset-neighborhood-strong-edge" : "asset-neighborhood-weak-edge"}" data-weight="${fmt(weight)}" d="M${fmt(cx + x1 * s)},${fmt(cy + y1 * s)} Q${fmt(cx + mx * s)},${fmt(cy + my * s)} ${fmt(cx + x2 * s)},${fmt(cy + y2 * s)}" fill="none" stroke="${weight > 0.7 ? palette.accent : palette.stroke}" stroke-width="${fmt((1.1 + weight * 1.15) * s)}" opacity="${fmt(0.28 + weight * 0.36)}" stroke-linecap="round"/>`;
  }).join("");
  const cellNodes = nodes.map(([x, y, scale], index) => {
    const px = cx + x * s;
    const py = cy + y * s;
    const path = organicPath(px, py, s * scale, 6 + (index % 3), 0.84);
    const selected = index === 1 || index === 6;
    const fill = selected ? palette.fill : index % 2 ? palette.secondary : "#ffffff";
    const halo = selected ? `<ellipse class="asset-neighborhood-node-halo" cx="${fmt(px)}" cy="${fmt(py + 1 * s)}" rx="${fmt(18 * s * scale)}" ry="${fmt(14 * s * scale)}" fill="${palette.accent}" opacity="0.13"/>` : "";
    const community = index === 0 || index === 1 || index === 4 ? "immune-niche" : index === 2 || index === 3 ? "tumor-edge" : "stromal-niche";
    return `<g class="asset-neighborhood-node ${selected ? "asset-neighborhood-hub-node" : ""}" data-node-index="${index}" data-community="${community}">${halo}<path d="${path}" fill="${fill}" stroke="${selected ? palette.stroke : palette.accent}" stroke-width="${fmt((selected ? 1.85 : 1.45) * s)}" stroke-linejoin="round"/><ellipse class="asset-neighborhood-node-nucleus" cx="${fmt(px - 2 * s)}" cy="${fmt(py)}" rx="${fmt(4.1 * s)}" ry="${fmt(2.8 * s)}" fill="${selected ? palette.secondary : palette.fill}" stroke="${palette.accent}" stroke-width="${fmt(0.85 * s)}" opacity="0.88"/></g>`;
  }).join("");
  const hull = `<path class="asset-neighborhood-community-hull" d="M${fmt(cx - 44 * s)},${fmt(cy - 24 * s)} C${fmt(cx - 24 * s)},${fmt(cy - 49 * s)} ${fmt(cx + 29 * s)},${fmt(cy - 45 * s)} ${fmt(cx + 47 * s)},${fmt(cy - 10 * s)} C${fmt(cx + 58 * s)},${fmt(cy + 21 * s)} ${fmt(cx + 25 * s)},${fmt(cy + 48 * s)} ${fmt(cx - 17 * s)},${fmt(cy + 43 * s)} C${fmt(cx - 54 * s)},${fmt(cy + 38 * s)} ${fmt(cx - 63 * s)},${fmt(cy + 1 * s)} ${fmt(cx - 44 * s)},${fmt(cy - 24 * s)} Z" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.6 * s)}" stroke-dasharray="${fmt(5 * s)} ${fmt(4 * s)}" opacity="0.46"/>`;
  const communityPatches = `<ellipse class="asset-neighborhood-community-patch" data-community="immune-niche" cx="${fmt(cx - 22 * s)}" cy="${fmt(cy + 0 * s)}" rx="${fmt(26 * s)}" ry="${fmt(35 * s)}" fill="${palette.secondary}" opacity="0.18"/><ellipse class="asset-neighborhood-community-patch" data-community="tumor-edge" cx="${fmt(cx + 26 * s)}" cy="${fmt(cy - 6 * s)}" rx="${fmt(26 * s)}" ry="${fmt(30 * s)}" fill="${palette.accent}" opacity="0.11"/>`;
  const centroid = `<g class="asset-neighborhood-centroid"><circle cx="${fmt(cx - 2 * s)}" cy="${fmt(cy + 3 * s)}" r="${fmt(4.4 * s)}" fill="#ffffff" stroke="${palette.stroke}" stroke-width="${fmt(1.25 * s)}"/><path d="M${fmt(cx - 7 * s)},${fmt(cy + 3 * s)} h${fmt(10 * s)} M${fmt(cx - 2 * s)},${fmt(cy - 2 * s)} v${fmt(10 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(0.9 * s)}" stroke-linecap="round"/></g>`;
  const legend = `<g class="asset-neighborhood-legend"><path d="M${fmt(cx - 42 * s)},${fmt(cy + 35 * s)} h${fmt(15 * s)}" stroke="${palette.accent}" stroke-width="${fmt(2.1 * s)}" stroke-linecap="round" opacity="0.78"/><circle cx="${fmt(cx - 22 * s)}" cy="${fmt(cy + 35 * s)}" r="${fmt(2.5 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(0.8 * s)}"/></g>`;
  const badge = `<g class="asset-neighborhood-knn-badge"><rect x="${fmt(cx + 24 * s)}" y="${fmt(cy - 42 * s)}" width="${fmt(31 * s)}" height="${fmt(18 * s)}" rx="${fmt(7 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.35 * s)}"/><text x="${fmt(cx + 39.5 * s)}" y="${fmt(cy - 29.4 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(7 * s)}" font-weight="900" fill="${palette.accent}">kNN</text></g>`;
  return `${baseLayer(cx, cy, s, palette)}<g filter="url(#asset-soft-shadow)">${communityPatches}${hull}${edges}${cellNodes}${centroid}${legend}${badge}<path class="asset-neighborhood-ground-shadow" d="M${fmt(cx - 39 * s)},${fmt(cy + 36 * s)} C${fmt(cx - 10 * s)},${fmt(cy + 48 * s)} ${fmt(cx + 22 * s)},${fmt(cy + 45 * s)} ${fmt(cx + 46 * s)},${fmt(cy + 30 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(1.4 * s)}" opacity="0.26" stroke-linecap="round"/></g>`;
}

