  const betaSheets = [[-28, 23, 18], [-8, 30, 17], [13, 24, 18]].map(([x, y, w], index) => `<path class="asset-protein-beta" d="M${fmt(cx + x * s)},${fmt(cy + y * s)} h${fmt(w * s)} l${fmt(5 * s)},${fmt(-5 * s)} l${fmt(-5 * s)},${fmt(-5 * s)} h${fmt(-w * s)} q${fmt(-5 * s)},${fmt(5 * s)} 0,${fmt(10 * s)} Z" fill="${index === 1 ? palette.secondary : "#ffffff"}" stroke="${palette.accent}" stroke-width="${fmt(1.05 * s)}" opacity="0.9"/>`).join("");
  const pocket = `<path class="asset-binding-pocket" d="M${fmt(cx + 14 * s)},${fmt(cy - 29 * s)} C${fmt(cx + 25 * s)},${fmt(cy - 38 * s)} ${fmt(cx + 38 * s)},${fmt(cy - 29 * s)} ${fmt(cx + 35 * s)},${fmt(cy - 17 * s)} C${fmt(cx + 32 * s)},${fmt(cy - 7 * s)} ${fmt(cx + 14 * s)},${fmt(cy - 9 * s)} ${fmt(cx + 14 * s)},${fmt(cy - 21 * s)} Z" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.45 * s)}" opacity="0.94"/><circle class="asset-protein-pocket-ligand" cx="${fmt(cx + 25 * s)}" cy="${fmt(cy - 21 * s)}" r="${fmt(4.2 * s)}" fill="${palette.accent}" opacity="0.9"/><circle class="asset-protein-phospho-site" cx="${fmt(cx - 23 * s)}" cy="${fmt(cy - 24 * s)}" r="${fmt(4.7 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.15 * s)}"/><path class="asset-protein-fold-trace" d="M${fmt(cx - 38 * s)},${fmt(cy + 9 * s)} C${fmt(cx - 20 * s)},${fmt(cy + 1 * s)} ${fmt(cx - 7 * s)},${fmt(cy + 13 * s)} ${fmt(cx + 4 * s)},${fmt(cy + 3 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(1.55 * s)}" opacity="0.34" stroke-linecap="round"/>`;
