  const miniProtein = (x, y, scale = 1, selected = false) => `<g class="asset-protein-engineering-mini-protein"><path d="M${fmt(cx + (x - 16 * scale) * s)},${fmt(cy + (y - 2 * scale) * s)} C${fmt(cx + (x - 20 * scale) * s)},${fmt(cy + (y - 14 * scale) * s)} ${fmt(cx + (x - 2 * scale) * s)},${fmt(cy + (y - 19 * scale) * s)} ${fmt(cx + (x + 5 * scale) * s)},${fmt(cy + (y - 10 * scale) * s)} C${fmt(cx + (x + 16 * scale) * s)},${fmt(cy + (y - 17 * scale) * s)} ${fmt(cx + (x + 24 * scale) * s)},${fmt(cy + (y - 1 * scale) * s)} ${fmt(cx + (x + 11 * scale) * s)},${fmt(cy + (y + 10 * scale) * s)} C${fmt(cx + (x - 6 * scale) * s)},${fmt(cy + (y + 19 * scale) * s)} ${fmt(cx + (x - 23 * scale) * s)},${fmt(cy + (y + 9 * scale) * s)} ${fmt(cx + (x - 16 * scale) * s)},${fmt(cy + (y - 2 * scale) * s)} Z" fill="${selected ? palette.accent : palette.secondary}" stroke="${palette.stroke}" stroke-width="${fmt(1.15 * s)}" opacity="${selected ? 0.92 : 0.72}"/><circle cx="${fmt(cx + (x + 9 * scale) * s)}" cy="${fmt(cy + (y - 7 * scale) * s)}" r="${fmt(2.3 * scale * s)}" fill="#ffffff" opacity="0.8"/></g>`;
  const plotAxes = `<path class="asset-protein-engineering-axis" d="M${fmt(cx - 34 * s)},${fmt(cy + 22 * s)} H${fmt(cx + 37 * s)} M${fmt(cx - 34 * s)},${fmt(cy + 22 * s)} V${fmt(cy - 22 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(1.5 * s)}" stroke-linecap="round" opacity="0.72"/>`;
