function standardFamily(family, cx, cy, s, palette, id) {
  if (family === "cell") return cellAsset(cx, cy, s, palette, { lobes: 6, nucleus: "round", granules: 5 });
  if (family === "molecule") return id?.includes("antibody") ? antibodyAsset(cx, cy, s, palette) : helixAsset(cx, cy, s, palette, "dna");
  if (family === "perturbation") return crisprAsset(cx, cy, s, palette);
  if (family === "instrument") return sequencerAsset(cx, cy, s, palette);
  if (family === "spatial") return spatialAsset(cx, cy, s, palette, "grid");
  if (family === "pathway") return pathwayAsset(cx, cy, s, palette);
  if (family === "organ") return organAsset(cx, cy, s, palette);
  if (family === "pathogen") return id?.includes("virus") ? virusAsset(cx, cy, s, palette) : pathogenStandard(cx, cy, s, palette);
  if (family === "space") return spaceAsset(cx, cy, s, palette);
  if (family === "modelSystem") return modelBlock(cx, cy, s, palette, "model");
  if (family === "dataSystem") return dataStack(cx, cy, s, palette);
  if (family === "agentSystem") return agentLoop(cx, cy, s, palette);
  if (family === "metricPanel") return metricCard(cx, cy, s, palette);
  if (family === "riskGate") return riskGate(cx, cy, s, palette);
  if (family === "governance") return humanReview(cx, cy, s, palette);
  return workflowBlock(cx, cy, s, palette);
}

