function workflowBlock(cx, cy, s, palette) {
  return `${baseLayer(cx, cy, s, palette, "panel")}<rect x="${fmt(cx - 47 * s)}" y="${fmt(cy - 32 * s)}" width="${fmt(94 * s)}" height="${fmt(64 * s)}" rx="${fmt(16 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.1 * s)}" filter="url(#asset-soft-shadow)"/><path d="M${fmt(cx - 28 * s)},${fmt(cy)} H${fmt(cx + 22 * s)}" stroke="${palette.accent}" stroke-width="${fmt(2.6 * s)}" stroke-linecap="round"/><path d="M${fmt(cx + 12 * s)},${fmt(cy - 11 * s)} L${fmt(cx + 26 * s)},${fmt(cy)} L${fmt(cx + 12 * s)},${fmt(cy + 11 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.6 * s)}" stroke-linecap="round" stroke-linejoin="round"/>`;
}

function normalizeLabelText(text) {
  return String(text ?? "").trim().replace(/\s+/g, " ");
}

function truncateLabelSegment(value, maxChars) {
  const clean = normalizeLabelText(value);
  if (clean.length <= maxChars) return clean;
  if (maxChars <= 3) return clean.slice(0, Math.max(1, maxChars));
  return `${clean.slice(0, Math.max(1, maxChars - 3)).replace(/[ .-]+$/, "")}...`;
}

function fitLabelLines(text, maxChars) {
  const clean = normalizeLabelText(text);
  if (!clean) return [""];
  if (clean.length <= maxChars) return [clean];
  const lines = [];
  let current = "";
  for (const word of clean.split(" ")) {
    const next = current ? `${current} ${word}` : word;
    if (next.length <= maxChars || !current) {
      current = next;
    } else {
      lines.push(current);
      current = word;
    }
  }
  if (current) lines.push(current);
  if (lines.length <= 2) return lines.map((line) => truncateLabelSegment(line, maxChars));
  return [truncateLabelSegment(lines[0], maxChars), truncateLabelSegment(lines.slice(1).join(" "), maxChars)];
}

function renderLabel(text, width, height, palette) {
  const fontSize = Math.max(8, Math.min(11.5, width / 13.8, height / 8.2));
  const maxChars = Math.max(7, Math.floor((width - 14) / (fontSize * 0.56)));
  const lines = fitLabelLines(text, maxChars);
  const lineGap = fontSize + 1.4;
  const baselineY = height - Math.max(6, Math.min(9, height * 0.075));
  const firstY = lines.length === 1 ? baselineY : baselineY - lineGap;
  if (palette.styleProfile === "publication-line") return renderPublicationLineLabel(lines, width, fontSize, lineGap, firstY, maxChars, palette);
  const pillPadY = 2.2;
  const pillHeight = fontSize + (lines.length - 1) * lineGap + pillPadY * 2;
  const pillY = Math.max(2, firstY - fontSize + 1.2 - pillPadY);
  const darkLabel = /^#(?:f|e)/i.test(String(palette.text ?? ""));
  const pillFill = darkLabel ? "#0f172a" : "#ffffff";
  const pillStroke = darkLabel ? "#334155" : "#dbe4f0";
  const tspans = lines.map((line, index) => index === 0
    ? `<tspan x="${fmt(width / 2)}" y="${fmt(firstY)}">${escapeXml(line)}</tspan>`
    : `<tspan x="${fmt(width / 2)}" dy="${fmt(lineGap)}">${escapeXml(line)}</tspan>`).join("");
  return `<g class="asset-label asset-label-fit" data-label-lines="${lines.length}" data-label-max-chars="${maxChars}"><rect class="asset-label-pill" x="${fmt(5)}" y="${fmt(pillY)}" width="${fmt(width - 10)}" height="${fmt(pillHeight)}" rx="${fmt(Math.min(8, pillHeight / 2))}" fill="${pillFill}" stroke="${pillStroke}" stroke-width="${fmt(0.8)}" opacity="0.92"/><text x="${fmt(width / 2)}" text-anchor="middle" fill="${palette.text}" font-family="Inter, Arial, sans-serif" font-size="${fmt(fontSize)}" font-weight="760">${tspans}</text></g>`;
}

function renderPublicationLineLabel(lines, width, fontSize, lineGap, firstY, maxChars, palette) {
  const labelWidth = Math.min(width - 12, Math.max(28, Math.max(...lines.map((line) => line.length)) * fontSize * 0.52 + 8));
  const ruleY = firstY - fontSize - 2.2;
  const tspans = lines.map((line, index) => index === 0
    ? `<tspan x="${fmt(width / 2)}" y="${fmt(firstY)}">${escapeXml(line)}</tspan>`
    : `<tspan x="${fmt(width / 2)}" dy="${fmt(lineGap)}">${escapeXml(line)}</tspan>`).join("");
  return `<g class="asset-label asset-label-fit asset-journal-label" data-label-lines="${lines.length}" data-label-max-chars="${maxChars}"><path class="asset-journal-label-rule" d="M${fmt((width - labelWidth) / 2)},${fmt(ruleY)} H${fmt((width + labelWidth) / 2)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(0.7)}" opacity="0.62"/><text class="asset-journal-label-text" x="${fmt(width / 2)}" text-anchor="middle" fill="${palette.text}" font-family="Inter, Arial, sans-serif" font-size="${fmt(fontSize)}" font-weight="690">${tspans}</text></g>`;
}

function renderAnchors(width, height) {
  const points = [[width / 2, 4], [width - 4, height * 0.42], [width / 2, height - 18], [4, height * 0.42]];
  return `<g class="asset-anchors" opacity="0" pointer-events="none">${points.map(([x, y], i) => `<circle data-anchor="${i}" cx="${fmt(x)}" cy="${fmt(y)}" r="3" fill="#2563eb"/>`).join("")}</g>`;
}

function normalizeAsset(assetOrId) {
  if (typeof assetOrId !== "string") {
    const id = assetOrId?.id ?? "fallback";
    const family = assetOrId?.family ?? assetOrId?.renderSpec?.family ?? inferFamily(id);
    return {
      ...assetOrId,
      id,
      name: assetOrId?.name ?? id,
      family,
      renderSpec: {
        family,
        accent: assetOrId?.renderSpec?.accent ?? "#2563eb",
        secondary: assetOrId?.renderSpec?.secondary ?? "#dbeafe",
        ...assetOrId?.renderSpec
      }
    };
  }
  const family = inferFamily(assetOrId);
  return {
    id: assetOrId,
    name: assetOrId,
    family,
    renderSpec: {
      family,
      accent: "#2563eb",
      secondary: "#dbeafe"
    }
  };
}

function variantPalette(asset, variant, appearance = {}, styleProfile = "consulting-2p5d", detailLevel = "medium") {
  const accent = asset.renderSpec?.accent ?? "#2563eb";
  const secondary = asset.renderSpec?.secondary ?? "#dbeafe";
  let palette;
  if (styleProfile === "publication-line") palette = { fill: "#ffffff", secondary: "#ffffff", accent: "#111827", stroke: "#111827", text: "#111827", contactOpacity: 0.035, surfaceOpacity: 0.04, depthOpacity: 0.08, glowOpacity: 0.08, strokeScale: 0.82 };
  else if (styleProfile === "minimal-flat") palette = { fill: secondary, secondary: "#ffffff", accent, stroke: accent, text: "#0f172a", contactOpacity: 0.055, surfaceOpacity: 0.08, depthOpacity: 0.18, glowOpacity: 0.1, strokeScale: 0.9 };
  else if (styleProfile === "dark-talk") palette = { fill: "#1e293b", secondary: "#334155", accent: "#38bdf8", stroke: "#e2e8f0", text: "#f8fafc", contactOpacity: 0.2, surfaceOpacity: 0.28, depthOpacity: 0.62, glowOpacity: 0.2, strokeScale: 1 };
  else if (styleProfile === "risk-warning") palette = { fill: "#fee2e2", secondary: "#fff7ed", accent: "#dc2626", stroke: "#991b1b", text: "#7f1d1d", contactOpacity: 0.18, surfaceOpacity: 0.24, depthOpacity: 0.66, glowOpacity: 0.22, strokeScale: 1.06 };
  else if (variant === "outline") palette = { fill: "#ffffff", secondary: "#ffffff", accent, stroke: accent, text: "#0f172a", contactOpacity: 0.06, surfaceOpacity: 0.08, depthOpacity: 0.14, glowOpacity: 0.08, strokeScale: 0.92 };
  else if (variant === "dark") palette = { fill: "#1e293b", secondary: "#334155", accent: "#38bdf8", stroke: "#e2e8f0", text: "#f8fafc", contactOpacity: 0.2, surfaceOpacity: 0.28, depthOpacity: 0.62, glowOpacity: 0.2, strokeScale: 1 };
  else if (variant === "warning") palette = { fill: "#fee2e2", secondary: "#fff7ed", accent: "#dc2626", stroke: "#991b1b", text: "#7f1d1d", contactOpacity: 0.18, surfaceOpacity: 0.24, depthOpacity: 0.66, glowOpacity: 0.22, strokeScale: 1.06 };
  else if (variant === "disabled") palette = { fill: "#e2e8f0", secondary: "#f1f5f9", accent: "#94a3b8", stroke: "#64748b", text: "#64748b", contactOpacity: 0.07, surfaceOpacity: 0.12, depthOpacity: 0.22, glowOpacity: 0.05, strokeScale: 0.86 };
  else if (variant === "selected") palette = { fill: "#dbeafe", secondary: "#eff6ff", accent: "#2563eb", stroke: "#1d4ed8", text: "#0f172a", contactOpacity: 0.18, surfaceOpacity: 0.22, depthOpacity: 0.7, glowOpacity: 0.14, strokeScale: 1 };
  else if (variant === "filled") palette = { fill: secondary, secondary: "#ffffff", accent, stroke: "#0f172a", text: "#0f172a", contactOpacity: 0.12, surfaceOpacity: 0.16, depthOpacity: 0.4, glowOpacity: 0.08, strokeScale: 0.95 };
  else palette = { fill: secondary, secondary: "#ffffff", accent, stroke: accent, text: "#0f172a", contactOpacity: 0.16, surfaceOpacity: 0.2, depthOpacity: 0.74, glowOpacity: 0.18, strokeScale: 1 };
  return {
    ...palette,
    styleProfile,
    detailLevel,
    accent: appearance.accent ?? palette.accent,
    secondary: appearance.secondary ?? palette.secondary,
    fill: appearance.fill ?? palette.fill,
    stroke: appearance.stroke ?? appearance.accent ?? palette.stroke,
    text: appearance.labelColor ?? palette.text,
    strokeScale: appearance.strokeWidth ? appearance.strokeWidth / 2 : palette.strokeScale
  };
}

function finishRenderedAssetMarkup(markup, palette) {
  let next = markup;
  if (palette.styleProfile === "publication-line") {
    next = next
      .replace(/\sfilter="url\(#asset-(?:soft-shadow|contact-shadow|warning-glow)\)"/g, "")
      .replace(/<(?:path|ellipse|circle|rect)[^>]*class="[^"]*(?:asset-(?:contact-shadow|soft-body-gradient|body-depth-overlay|inner-highlight|warning-glow|rim-highlight)|asset-(?:tcell|bcell|immune-cell|macrophage|tumor-cell|protein|receptor-membrane|scrna-oil|cell-barcode|metabolite|enzyme|tissue)[\w-]*-rim\b)[^"]*"[^>]*>/g, "")
      .replace(/<(?:path|ellipse|circle|rect)[^>]*fill="url\(#asset-(?:glass-highlight|body-depth)\)"[^>]*>/g, "")
      .replace(/stroke="#ffffff"/g, `stroke="${palette.stroke}"`);
    next = squarePublicationLineUiRects(next);
    next = stripPublicationLineBiologyChrome(next);
  }
  if (palette.styleProfile === "minimal-flat" || palette.detailLevel === "low") {
    next = next
      .replace(/\sfilter="url\(#asset-(?:soft-shadow|contact-shadow|warning-glow)\)"/g, "")
      .replace(/<[^>]*class="asset-(?:contact-shadow|body-depth-overlay|inner-highlight|warning-glow|rim-highlight)"[^>]*>/g, "")
      .replace(/ opacity="0\.(?:4[0-9]|5[0-9]|6[0-9]|7[0-9])"/g, ' opacity="0.34"');
  }
  if (palette.styleProfile === "dark-talk") {
    next = next.replace(/stroke="#ffffff"/g, 'stroke="#e2e8f0"');
  }
  return next;
}

function squarePublicationLineUiRects(markup) {
  const uiClassPattern = "asset-(?:dataset|benchmark|metric|calibration|permission|human-review|audit-log|bio-classifier|model-block|foundation-model|classifier|context-window|memory|planner|executor|function-schema|tool-call|mcp-server|agent-loop|expression-matrix|gene-track|gene-exon|chromatin-methyl|chromatin-epigenetic|policy-stack|review|blocked-output|approval-stamp|bio-protocol|protocol-risk|safety-classifier|gene-synthesis|dual-use|escalation)[\\w-]*";
  const uiRect = new RegExp(`(<rect\\b[^>]*\\bclass="[^"]*(?:${uiClassPattern})[^"]*"[^>]*?)\\s+rx="[^"]+"`, "g");
  return markup.replace(uiRect, "$1 rx=\"0\"");
}

function stripPublicationLineBiologyChrome(markup) {
  const chromeClasses = [
    "asset-gene-locus-frame",
    "asset-gene-track-ruler",
    "asset-metabolite-badge",
    "asset-cascade-label"
  ];
  const chromePattern = chromeClasses.join("|");
  const chromeRect = new RegExp(`<rect\\b[^>]*\\bclass="[^"]*(?:${chromePattern})[^"]*"[^>]*>`, "g");
  return markup.replace(chromeRect, "");
}

function inferFamily(assetId = "") {
  if (/dna|rna|gene|protein|antibody|receptor|ligand|cytokine|metabolite|chromatin|nucleosome|compound|lead-series/.test(assetId)) return "molecule";
  if (/umi|read|peak|genome-browser|variant|copy-number/.test(assetId)) return "molecule";
  if (/crispr|guide|screen|perturb|knockdown|activation|inhibition|editor|drug|target-validation|target-engagement|candidate-nomination|medicinal-chemistry-cycle|efficacy-model|ind-enabling-package/.test(assetId)) return "perturbation";
  if (/microscope|sequencer|plate|pipette|centrifuge|incubator|cytometer|sorter|machine|spectrometer|handler|cabinet/.test(assetId)) return "instrument";
  if (/spatial|visium|merfish|xenium|histology|tile|mask|boundary|neighborhood|registration|morphology/.test(assetId)) return "spatial";
  if (/dataset|store|data|label|pipeline/.test(assetId)) return "dataSystem";
  if (/benchmark|metric|matrix|curve|analysis|judge|rubric|leaderboard|ablation|interval|failure|gold|hit-triage|admet|selectivity-panel|pk-profile|sar-table|biomarker-response/.test(assetId)) return "metricPanel";
  if (/risk|policy|permission|refusal|review|audit|red-team|escalation|safety|filter|blocked|threat|biosecurity|durc|biosafety|dual-use|toxicity/.test(assetId)) return "riskGate";
  if (/model|network|transformer|training|inference|classifier|foundation|tuning|prediction|embedding/.test(assetId)) return "modelSystem";
  if (/prompt|context|retrieval|memory|tool|planner|executor|mcp|agent|router|scratchpad|schema/.test(assetId)) return "agentSystem";
  if (/microgravity|spacecraft|astronaut|spaceflight|genelab|mission/.test(assetId)) return "space";
  if (/cohort|organoid|mouse/.test(assetId)) return "organ";
  if (/muscle|hepatocyte|blood/.test(assetId)) return "cell";
  if (/deployment|monitoring|governance|incident|traceability|drift/.test(assetId)) return "governance";
  return "cell";
}

function fmt(value) {
  return Number.isFinite(value) ? Number(value.toFixed(3)).toString() : "0";
}

function normalizeAppearance(input = {}) {
  return {
    accent: safeColor(input.accent),
    secondary: safeColor(input.secondary),
    fill: safeColor(input.fill),
    stroke: safeColor(input.stroke),
    labelColor: safeColor(input.labelColor ?? input.text),
    strokeWidth: clampNumber(input.strokeWidth, 0.5, 8),
    styleProfile: ASSET_STYLE_PROFILES.includes(input.styleProfile) ? input.styleProfile : undefined,
    detailLevel: ["low", "medium", "high"].includes(input.detailLevel) ? input.detailLevel : undefined
  };
}

function safeColor(value) {
  if (typeof value !== "string") return undefined;
  const trimmed = value.trim();
  if (/^#[0-9a-fA-F]{3}([0-9a-fA-F]{3})?$/.test(trimmed)) return trimmed;
  if (/^rgba?\([0-9.,% /-]+\)$/.test(trimmed)) return trimmed;
  return undefined;
}

function clampNumber(value, min, max) {
  const number = Number(value);
  if (!Number.isFinite(number)) return undefined;
  return Math.max(min, Math.min(max, number));
}

function scaleStrokeWidths(markup, scale = 1) {
  if (!Number.isFinite(scale) || Math.abs(scale - 1) < 0.001) return markup;
  return markup.replace(/stroke-width="([0-9.]+)"/g, (_match, value) => `stroke-width="${fmt(Number(value) * scale)}"`);
}

function escapeXml(value) {
  return String(value).replace(/[&<>"']/g, (char) => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    '"': "&quot;",
    "'": "&apos;"
  })[char]);
}

function organicPath(cx, cy, s, lobes, wobble = 1) {
  const points = [];
  for (let i = 0; i < lobes; i += 1) {
    const a = (Math.PI * 2 * i) / lobes - Math.PI / 2;
    const r = (41 + (i % 3) * 5 + Math.sin(i * 1.7) * 3) * wobble;
    points.push([cx + Math.cos(a) * r * s, cy + Math.sin(a) * (r * 0.86) * s]);
  }
  return points.map(([x, y], i) => {
    const [px, py] = points[(i - 1 + points.length) % points.length];
    const [nx, ny] = points[(i + 1) % points.length];
    const c1x = x + (nx - px) * 0.13;
    const c1y = y + (ny - py) * 0.13;
    const [nextX, nextY] = points[(i + 1) % points.length];
    return `${i === 0 ? `M${fmt(x)},${fmt(y)}` : ""} C${fmt(c1x)},${fmt(c1y)} ${fmt(nextX - (points[(i + 2) % points.length][0] - x) * 0.13)},${fmt(nextY - (points[(i + 2) % points.length][1] - y) * 0.13)} ${fmt(nextX)},${fmt(nextY)}`;
  }).join(" ") + " Z";
}

function beanPath(cx, cy, s) {
  return `M${fmt(cx - 14 * s)},${fmt(cy - 6 * s)} C${fmt(cx - 10 * s)},${fmt(cy - 22 * s)} ${fmt(cx + 16 * s)},${fmt(cy - 17 * s)} ${fmt(cx + 13 * s)},${fmt(cy + 2 * s)} C${fmt(cx + 10 * s)},${fmt(cy + 20 * s)} ${fmt(cx - 17 * s)},${fmt(cy + 18 * s)} ${fmt(cx - 14 * s)},${fmt(cy - 6 * s)} Z`;
}

function scatterDots(cx, cy, s, count, color, opacity = 0.75) {
  const dots = [];
  for (let i = 0; i < count; i += 1) {
    const a = i * 2.399;
    const r = (6 + (i % 5) * 5.2) * s;
    dots.push(`<circle cx="${fmt(cx + Math.cos(a) * r)}" cy="${fmt(cy + Math.sin(a) * r * 0.78)}" r="${fmt((2.1 + (i % 3) * 0.7) * s)}" fill="${color}" opacity="${opacity}"/>`);
  }
  return dots.join("");
}

function receptorMarks(cx, cy, s, color, kind) {
  if (kind === "fork") {
    return `<path d="M${fmt(cx)},${fmt(cy)} v${fmt(16 * s)} M${fmt(cx)},${fmt(cy + 7 * s)} l${fmt(-11 * s)},${fmt(-11 * s)} M${fmt(cx)},${fmt(cy + 7 * s)} l${fmt(11 * s)},${fmt(-11 * s)}" fill="none" stroke="${color}" stroke-width="${fmt(2.2 * s)}" stroke-linecap="round"/>`;
  }
  return `<path d="M${fmt(cx)},${fmt(cy)} v${fmt(16 * s)} M${fmt(cx - 8 * s)},${fmt(cy)} h${fmt(16 * s)} M${fmt(cx + 5 * s)},${fmt(cy + 21 * s)} v${fmt(13 * s)} M${fmt(cx - 2 * s)},${fmt(cy + 21 * s)} h${fmt(14 * s)}" fill="none" stroke="${color}" stroke-width="${fmt(2 * s)}" stroke-linecap="round"/>`;
}

function surfaceSpikes(cx, cy, s, color, kind) {
  if (kind === "bcr") {
    return [-15, -2, 11].map((y, index) => {
      const x = cx + (index % 2 ? 3 : 0) * s;
      return `<path d="M${fmt(x)},${fmt(cy + y * s)} v${fmt(16 * s)} M${fmt(x)},${fmt(cy + (y + 6) * s)} l${fmt(-9 * s)},${fmt(-8 * s)} M${fmt(x)},${fmt(cy + (y + 6) * s)} l${fmt(9 * s)},${fmt(-8 * s)}" fill="none" stroke="${color}" stroke-width="${fmt((index === 1 ? 2.15 : 1.75) * s)}" stroke-linecap="round" opacity="0.88"/>`;
    }).join("");
  }
  if (kind === "tcr") {
    return [-13, 5, 22].map((y, index) => {
      const x = cx + (index === 1 ? 5 : 0) * s;
      return `<path d="M${fmt(x)},${fmt(cy + y * s)} v${fmt(15 * s)} M${fmt(x - 7 * s)},${fmt(cy + (y + 2) * s)} h${fmt(14 * s)}" fill="none" stroke="${color}" stroke-width="${fmt(1.9 * s)}" stroke-linecap="round" opacity="0.84"/>`;
    }).join("");
  }
  return [-17, -3, 12].map((y, index) => {
    const x = cx + (index === 1 ? 4 : 0) * s;
    return `<path d="M${fmt(x)},${fmt(cy + y * s)} c${fmt(7 * s)},${fmt(-4 * s)} ${fmt(9 * s)},${fmt(-10 * s)} ${fmt(5 * s)},${fmt(-15 * s)}" fill="none" stroke="${color}" stroke-width="${fmt(1.85 * s)}" stroke-linecap="round" opacity="0.78"/>`;
  }).join("");
}

function shine(cx, cy, s) {
  return `<ellipse class="asset-inner-highlight" cx="${fmt(cx)}" cy="${fmt(cy)}" rx="${fmt(18 * s)}" ry="${fmt(6.5 * s)}" fill="#ffffff" opacity="0.42"/>`;
}

function virusParticle(cx, cy, r, palette) {
  const spikes = [];
  for (let i = 0; i < 14; i += 1) {
    const a = (Math.PI * 2 * i) / 14;
    const stem = `<path class="asset-virus-spike" d="M${fmt(cx + Math.cos(a) * (r - 1))},${fmt(cy + Math.sin(a) * (r - 1))} L${fmt(cx + Math.cos(a) * (r + 8))},${fmt(cy + Math.sin(a) * (r + 8))}" stroke="${palette.stroke}" stroke-width="${fmt(2)}" stroke-linecap="round"/>`;
    const head = `<circle class="asset-virus-spike" cx="${fmt(cx + Math.cos(a) * (r + 10))}" cy="${fmt(cy + Math.sin(a) * (r + 10))}" r="${fmt(2.2)}" fill="${palette.secondary}" stroke="${palette.stroke}" stroke-width="${fmt(0.8)}"/>`;
    spikes.push(`${stem}${head}`);
  }
  return `<g filter="url(#asset-soft-shadow)">${spikes.join("")}<circle class="asset-virus-capsid" cx="${fmt(cx)}" cy="${fmt(cy)}" r="${fmt(r)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.2)}"/><circle class="asset-virus-capsid" cx="${fmt(cx)}" cy="${fmt(cy)}" r="${fmt(r * 0.72)}" fill="url(#asset-glass-highlight)" opacity="0.38"/><circle cx="${fmt(cx - r * 0.32)}" cy="${fmt(cy - r * 0.22)}" r="${fmt(r * 0.19)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.1)}"/><circle cx="${fmt(cx + r * 0.35)}" cy="${fmt(cy + r * 0.25)}" r="${fmt(r * 0.22)}" fill="${palette.accent}" opacity="0.85"/><path class="asset-virus-genome" d="M${fmt(cx - r * 0.28)},${fmt(cy + r * 0.05)} C${fmt(cx - r * 0.05)},${fmt(cy - r * 0.18)} ${fmt(cx + r * 0.18)},${fmt(cy + r * 0.25)} ${fmt(cx + r * 0.34)},${fmt(cy - r * 0.03)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(1.45)}" opacity="0.54" stroke-linecap="round"/></g>`;
}

function crisprMini(cx, cy, s, palette) {
  return `<rect x="${fmt(cx - 2 * s)}" y="${fmt(cy - 32 * s)}" width="${fmt(32 * s)}" height="${fmt(17 * s)}" rx="${fmt(6 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.8 * s)}"/><text x="${fmt(cx + 14 * s)}" y="${fmt(cy - 20 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(8 * s)}" font-weight="900" fill="${palette.accent}">Cas9</text>`;
}
